import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useCampaigns } from '@/hooks/useCampaigns';
import { supabase } from '@/integrations/supabase/client';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Checkbox } from "@/components/ui/checkbox";
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from '@/components/ui/select';
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow,
} from '@/components/ui/table';
import {
    Megaphone,
    Search,
    Filter,
    Play,
    Pause,
    MoreHorizontal,
    Loader2,
    Eye,
    TrendingUp,
    ListChecks,
    X,
    ChevronLeft,
    ChevronRight,
    ArrowUpRight,
    Zap,
    Sparkles,
    ShieldCheck,
    Briefcase,
    Activity,
    Target,
    BarChart3,
    MousePointerClick,
    RefreshCw
} from 'lucide-react';
import {
    DropdownMenu,
    DropdownMenuContent,
    DropdownMenuItem,
    DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu';
import { formatDistanceToNow } from 'date-fns';
import { ptBR } from 'date-fns/locale';
import { toast } from 'sonner';
import { useQueryClient } from '@tanstack/react-query';
import { TagList } from '@/components/tags/TagBadge';
import { TagSelector } from '@/components/tags/TagSelector';
import { motion, AnimatePresence } from 'framer-motion';

const PAGE_SIZE = 12;

const formatCurrency = (value: number) => {
    return new Intl.NumberFormat('pt-BR', {
        style: 'currency',
        currency: 'BRL',
    }).format(value);
};

const formatNumber = (value: number) => {
    if (value >= 1000000) return `${(value / 1000000).toFixed(1)}M`;
    if (value >= 1000) return `${(value / 1000).toFixed(1)}K`;
    return value.toLocaleString('pt-BR');
};

const container = {
    hidden: { opacity: 0 },
    show: {
        opacity: 1,
        transition: {
            staggerChildren: 0.05
        }
    }
};

const item = {
    hidden: { opacity: 0, y: 15 },
    show: { opacity: 1, y: 0 }
};

export default function Campanhas() {
    const navigate = useNavigate();
    const queryClient = useQueryClient();
    const [search, setSearch] = useState('');
    const [statusFilter, setStatusFilter] = useState<string>('all');
    const [page, setPage] = useState(0);
    const [selectedIds, setSelectedIds] = useState<string[]>([]);
    const [isBulkProcessing, setIsBulkProcessing] = useState(false);

    // AI Diagnosis State
    const [isAiModalOpen, setIsAiModalOpen] = useState(false);
    const [isAiLoading, setIsAiLoading] = useState(false);
    const [selectedCampaignId, setSelectedCampaignId] = useState<string | null>(null);
    const [aiData, setAiData] = useState<any>(null);

    const handleRunDiagnosis = async (id: string) => {
        setSelectedCampaignId(id);
        setIsAiModalOpen(true);
        setIsAiLoading(true);
        setAiData(null);

        try {
            const { data: { session } } = await supabase.auth.getSession();
            if (!session) throw new Error('No session');

            const response = await fetch(`${import.meta.env.VITE_SUPABASE_URL}/functions/v1/audit-campaign`, {
                method: 'POST',
                headers: {
                    'Authorization': `Bearer ${session.access_token}`,
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify({ campaign_id: id }),
            });

            if (!response.ok) throw new Error('Falha na análise');
            const data = await response.json();
            setAiData(data);
        } catch (error) {
            console.error(error);
            toast.error('Erro ao executar diagnóstico IA');
            setIsAiModalOpen(false);
        } finally {
            setIsAiLoading(false);
        }
    };

    const { data, isLoading } = useCampaigns({
        search: search || undefined,
        status: statusFilter !== 'all' ? statusFilter : undefined,
        limit: PAGE_SIZE,
        offset: page * PAGE_SIZE,
    });

    const campaigns = data?.campaigns || [];
    const total = data?.total || 0;
    const totalPages = Math.ceil(total / PAGE_SIZE);

    const getStatusState = (status: string) => {
        const config: Record<string, { label: string, color: string, icon: any }> = {
            active: { label: 'Em Operação', color: 'emerald-500', icon: Play },
            paused: { label: 'Em Espera', color: 'amber-500', icon: Pause },
            deleted: { label: 'Removida', color: 'rose-500', icon: X },
            archived: { label: 'Legado', color: 'ch-text-dimmed', icon: RefreshCw },
        };
        return config[status] || config.paused;
    };

    const handleViewCampaign = (campaignId: string) => {
        navigate(`/campanhas/${campaignId}`);
    };

    const toggleSelectAll = () => {
        if (selectedIds.length === campaigns.length && campaigns.length > 0) {
            setSelectedIds([]);
        } else {
            setSelectedIds(campaigns.map(c => c.id));
        }
    };

    const toggleSelect = (id: string, checked: boolean) => {
        if (checked) {
            setSelectedIds(prev => [...prev, id]);
        } else {
            setSelectedIds(prev => prev.filter(i => i !== id));
        }
    };

    const executeAction = async (campaignId: string, action: string) => {
        const { data: { session } } = await supabase.auth.getSession();
        if (!session) throw new Error('No session');

        const response = await fetch(`${import.meta.env.VITE_SUPABASE_URL}/functions/v1/meta-campaign-action`, {
            method: 'POST',
            headers: {
                'Authorization': `Bearer ${session.access_token}`,
                'Content-Type': 'application/json',
            },
            body: JSON.stringify({
                campaign_id: campaignId,
                action,
            }),
        });

        if (!response.ok) {
            const error = await response.json();
            throw new Error(error.error || 'Failed to perform action');
        }
        return response.json();
    };

    const handleBulkAction = async (action: 'pause' | 'activate') => {
        if (selectedIds.length === 0) return;
        setIsBulkProcessing(true);
        let successCount = 0;
        let errorCount = 0;

        try {
            const promises = selectedIds.map(id =>
                executeAction(id, action)
                    .then(() => { successCount++; })
                    .catch(() => { errorCount++; })
            );

            await Promise.all(promises);

            if (successCount > 0) {
                toast.success(`${successCount} campanhas ${action === 'activate' ? 'ativadas' : 'pausadas'} com sucesso.`);
            }
            if (errorCount > 0) {
                toast.error(`Falha ao atualizar ${errorCount} campanhas.`);
            }

            setSelectedIds([]);
            queryClient.invalidateQueries({ queryKey: ['campaigns'] });

        } catch (error) {
            console.error(error);
            toast.error('Erro ao processar ação em massa.');
        } finally {
            setIsBulkProcessing(false);
        }
    };

    return (
        <motion.div
            initial="hidden"
            animate="show"
            variants={container}
            className="p-6 space-y-10"
        >
            {/* Header Area */}
            <motion.div variants={item} className="flex flex-col md:flex-row md:items-center justify-between gap-8">
                <div>
                    <div className="flex items-center gap-3 mb-1">
                        <Megaphone className="w-4 h-4 text-ch-orange" />
                        <span className="text-[10px] font-bold text-ch-orange uppercase tracking-wide">Operações Meta</span>
                    </div>
                    <h1 className="text-3xl font-bold text-ch-white tracking-tight uppercase">Gestor de Ecossistema</h1>
                    <p className="text-ch-text-muted font-medium mt-1">Visão holística e orquestração de alto nível para suas campanhas.</p>
                </div>

                <div className="flex items-center gap-4">
                    <Button
                        onClick={() => navigate('/campanhas/nova')}
                        className="bg-ch-white hover:bg-ch-orange text-ch-black font-black uppercase tracking-widest rounded-xl transition-all h-14 px-8 shadow-xl group"
                    >
                        <Zap className="w-4 h-4 mr-2 group-hover:animate-pulse" />
                        Lançar Campanha
                    </Button>
                </div>
            </motion.div>

            {/* Performance Snapshot */}
            <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
                {[
                    { label: 'Ecossistema', value: total, icon: BarChart3, color: 'ch-orange' },
                    { label: 'Performance', value: campaigns.filter(c => c.status === 'active').length, icon: Play, color: 'emerald-500' },
                    { label: 'Stand-by', value: campaigns.filter(c => c.status === 'paused').length, icon: Pause, color: 'amber-500' },
                    { label: 'Opex Total', value: formatCurrency(campaigns.reduce((acc, c) => acc + (c.spend || 0), 0)), icon: TrendingUp, color: 'blue-500' }
                ].map((stat) => (
                    <motion.div key={stat.label} variants={item} whileHover={{ y: -3 }} className="glass-card rounded-[2rem] p-6 border-white/5 shadow-xl group">
                        <div className="flex items-center gap-4 mb-4">
                            <div className={`p-2.5 bg-${stat.color}/10 rounded-xl`}>
                                <stat.icon className={`w-5 h-5 text-${stat.color}`} />
                            </div>
                            <span className="text-[10px] font-bold text-ch-text-muted uppercase tracking-widest leading-none">{stat.label}</span>
                        </div>
                        <p className="text-2xl font-bold text-ch-white tracking-tighter tabular-nums group-hover:text-ch-orange transition-colors">{stat.value}</p>
                    </motion.div>
                ))}
            </div>

            {/* Management & Filter Bar */}
            <motion.div variants={item} className="space-y-4">
                <AnimatePresence>
                    {selectedIds.length > 0 && (
                        <motion.div
                            initial={{ opacity: 0, scale: 0.98, y: 10 }}
                            animate={{ opacity: 1, scale: 1, y: 0 }}
                            exit={{ opacity: 0, scale: 0.98, y: 10 }}
                            className="bg-ch-white text-ch-black rounded-3xl p-5 flex items-center justify-between shadow-2xl relative z-20"
                        >
                            <div className="flex items-center gap-5">
                                <div className="flex items-center justify-center w-12 h-12 rounded-2xl bg-ch-black text-ch-white font-black text-xl shadow-xl">
                                    {selectedIds.length}
                                </div>
                                <div>
                                    <p className="font-bold uppercase text-xs tracking-tight">Ativos em Fila</p>
                                    <p className="text-[10px] font-bold uppercase tracking-widest text-ch-black/40">Comandos de Lote Disponíveis</p>
                                </div>
                            </div>
                            <div className="flex items-center gap-3">
                                <Button
                                    size="sm"
                                    className="bg-emerald-500 hover:bg-emerald-600 text-white font-black uppercase text-[10px] tracking-widest px-6 h-12 rounded-xl transition-all shadow-lg"
                                    onClick={() => handleBulkAction('activate')}
                                    disabled={isBulkProcessing}
                                >
                                    {isBulkProcessing ? <Loader2 className="w-4 h-4 animate-spin mr-2" /> : <Play className="w-4 h-4 mr-2" />}
                                    Ativar Todos
                                </Button>
                                <Button
                                    size="sm"
                                    className="bg-amber-500 hover:bg-amber-600 text-white font-black uppercase text-[10px] tracking-widest px-6 h-12 rounded-xl transition-all shadow-lg"
                                    onClick={() => handleBulkAction('pause')}
                                    disabled={isBulkProcessing}
                                >
                                    {isBulkProcessing ? <Loader2 className="w-4 h-4 animate-spin mr-2" /> : <Pause className="w-4 h-4 mr-2" />}
                                    Pausar Todos
                                </Button>
                                <div className="h-8 w-px bg-ch-black/10 mx-2" />
                                <Button
                                    variant="ghost"
                                    size="icon"
                                    className="text-ch-black/40 hover:text-ch-black hover:bg-transparent"
                                    onClick={() => setSelectedIds([])}
                                    disabled={isBulkProcessing}
                                >
                                    <X className="w-6 h-6" />
                                </Button>
                            </div>
                        </motion.div>
                    )}
                </AnimatePresence>

                <div className="flex flex-col md:flex-row items-center gap-4 bg-white/[0.02] border border-white/5 p-4 rounded-[1.5rem] backdrop-blur-sm">
                    <div className="relative flex-1 w-full">
                        <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-ch-text-dimmed" />
                        <Input
                            placeholder="LOCALIZAR CAMPANHA POR NOME OU ID..."
                            value={search}
                            onChange={(e) => {
                                setSearch(e.target.value);
                                setPage(0);
                            }}
                            className="pl-12 bg-transparent border-none text-[10px] font-bold uppercase tracking-[.1em] focus-visible:ring-0 placeholder:opacity-20"
                        />
                    </div>
                    <div className="h-6 w-px bg-white/5 hidden md:block" />
                    <Select
                        value={statusFilter}
                        onValueChange={(v) => {
                            setStatusFilter(v);
                            setPage(0);
                        }}
                    >
                        <SelectTrigger className="w-full md:w-56 bg-ch-dark-gray/40 border-white/5 h-12 rounded-xl text-[10px] font-black uppercase tracking-widest">
                            <Filter className="w-4 h-4 mr-2 text-ch-orange" />
                            <SelectValue placeholder="Estado Meta" />
                        </SelectTrigger>
                        <SelectContent className="bg-ch-black-soft border-white/10 font-black uppercase text-[10px] tracking-widest">
                            <SelectItem value="all">Sincronizar Tudo</SelectItem>
                            <SelectItem value="active" className="text-emerald-500">Operantes</SelectItem>
                            <SelectItem value="paused" className="text-amber-500">Em Espera</SelectItem>
                            <SelectItem value="archived">Legado</SelectItem>
                        </SelectContent>
                    </Select>
                </div>
            </motion.div>

            {/* Campaign Ledger */}
            <motion.div variants={item} className="glass rounded-[2rem] overflow-hidden border border-white/5 shadow-2xl transition-all">
                {isLoading ? (
                    <div className="p-32 flex flex-col items-center justify-center gap-6">
                        <div className="relative">
                            <RefreshCw className="w-16 h-16 animate-spin text-ch-orange opacity-20" />
                            <Zap className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-6 h-6 text-ch-orange" />
                        </div>
                        <div className="text-center">
                            <p className="text-[10px] font-black uppercase tracking-widest text-ch-orange mb-2">Sincronização de Dados</p>
                            <p className="text-ch-text-dimmed font-medium">Orquestrando dados através da API do Meta...</p>
                        </div>
                    </div>
                ) : campaigns.length > 0 ? (
                    <div className="overflow-x-auto">
                        <Table>
                            <TableHeader>
                                <TableRow className="border-white/5 hover:bg-transparent h-20 bg-white/[0.01]">
                                    <TableHead className="w-[80px] pl-8">
                                        <Checkbox
                                            className="border-white/20 data-[state=checked]:bg-ch-orange data-[state=checked]:border-ch-orange rounded-md"
                                            checked={selectedIds.length === campaigns.length && campaigns.length > 0}
                                            onCheckedChange={toggleSelectAll}
                                        />
                                    </TableHead>
                                    <TableHead className="text-[10px] font-bold uppercase tracking-[0.1em] text-ch-text-muted">Ativo / Identidade</TableHead>
                                    <TableHead className="text-[10px] font-bold uppercase tracking-[0.1em] text-ch-text-muted">Estado</TableHead>
                                    <TableHead className="text-[10px] font-bold uppercase tracking-[0.1em] text-ch-text-muted">Objetivo de Targeting</TableHead>
                                    <TableHead className="text-[10px] font-bold uppercase tracking-[0.1em] text-ch-text-muted text-right">Performance / Gasto</TableHead>
                                    <TableHead className="text-[10px] font-bold uppercase tracking-[0.1em] text-ch-text-muted text-right">Budgeting</TableHead>
                                    <TableHead className="w-[100px] pr-8"></TableHead>
                                </TableRow>
                            </TableHeader>
                            <TableBody>
                                {campaigns.map((campaign) => {
                                    const state = getStatusState(campaign.status);
                                    const StateIcon = state.icon;
                                    return (
                                        <TableRow
                                            key={campaign.id}
                                            className="border-white/5 hover:bg-white/[0.02] cursor-pointer group transition-all h-24"
                                            onClick={() => handleViewCampaign(campaign.id)}
                                        >
                                            <TableCell className="pl-8" onClick={(e) => e.stopPropagation()}>
                                                <Checkbox
                                                    className="border-white/20 data-[state=checked]:bg-ch-orange data-[state=checked]:border-ch-orange rounded-md"
                                                    checked={selectedIds.includes(campaign.id)}
                                                    onCheckedChange={(checked) => toggleSelect(campaign.id, checked as boolean)}
                                                />
                                            </TableCell>
                                            <TableCell>
                                                <div className="py-2">
                                                    <p className="font-bold text-ch-white group-hover:text-ch-orange transition-colors uppercase tracking-tight text-base">{campaign.name}</p>
                                                    <div className="flex items-center gap-3 mt-2">
                                                        <TagList tags={campaign.tags} />
                                                        <span className="text-[9px] font-bold text-ch-text-dimmed uppercase tracking-widest flex items-center gap-1.5 border-l border-white/10 pl-3">
                                                            <Activity className="w-3 h-3" /> Atualizado {formatDistanceToNow(new Date(campaign.updated_at), { addSuffix: true, locale: ptBR })}
                                                        </span>
                                                    </div>
                                                </div>
                                            </TableCell>
                                            <TableCell>
                                                <span className={`text-[9px] font-bold uppercase tracking-[0.1em] px-3 py-1.5 rounded-full border bg-${state.color}/10 text-${state.color} border-${state.color}/20 flex items-center gap-2 w-fit`}>
                                                    <StateIcon className="w-3 h-3" />
                                                    {state.label}
                                                </span>
                                            </TableCell>
                                            <TableCell>
                                                <div className="flex items-center gap-2 text-[10px] font-bold text-ch-text-muted uppercase tracking-widest px-3 py-1.5 bg-white/5 rounded-xl border border-white/10 w-fit">
                                                    <Target className="w-3.5 h-3.5 text-ch-orange" />
                                                    {campaign.objective?.replace(/_/g, ' ') || 'ENGAJAMENTO'}
                                                </div>
                                            </TableCell>
                                            <TableCell className="text-right">
                                                <div className="flex flex-col items-end gap-1.5">
                                                    <span className="text-base font-black text-ch-white tabular-nums">{formatCurrency(campaign.spend || 0)}</span>
                                                    <div className="flex items-center gap-3 text-[10px] font-bold text-ch-text-dimmed uppercase tracking-tighter">
                                                        <span className="flex items-center gap-1.5"><Eye className="w-3.5 h-3.5" /> {formatNumber(campaign.impressions || 0)}</span>
                                                        <span className="flex items-center gap-1.5"><MousePointerClick className="w-3.5 h-3.5" /> {formatNumber(campaign.clicks || 0)}</span>
                                                    </div>
                                                </div>
                                            </TableCell>
                                            <TableCell className="text-right">
                                                <div className="flex flex-col items-end bg-white/[0.03] p-3 rounded-2xl border border-white/5 w-fit ml-auto">
                                                    <span className="text-sm font-black text-ch-white tabular-nums">{campaign.daily_budget ? formatCurrency(campaign.daily_budget) : 'FLEXÍVEL'}</span>
                                                    <span className="text-[9px] font-black text-ch-text-muted tracking-widest mt-1 uppercase">Alocação Diária</span>
                                                </div>
                                            </TableCell>
                                            <TableCell className="pr-8 text-right" onClick={(e) => e.stopPropagation()}>
                                                <div className="flex items-center justify-end gap-3">
                                                    <div onClick={(e) => e.stopPropagation()}>
                                                        <TagSelector
                                                            entityId={campaign.id}
                                                            entityType="campaign"
                                                            selectedTags={campaign.tags || []}
                                                        />
                                                    </div>
                                                    <DropdownMenu>
                                                        <DropdownMenuTrigger asChild>
                                                            <Button variant="ghost" size="icon" className="h-10 w-10 hover:bg-white/10 rounded-xl transition-all border border-transparent hover:border-white/5">
                                                                <MoreHorizontal className="w-5 h-5" />
                                                            </Button>
                                                        </DropdownMenuTrigger>
                                                        <DropdownMenuContent align="end" className="bg-ch-black-soft border-white/10 w-56 p-2 shadow-2xl font-black uppercase text-[10px] tracking-[0.1em]">
                                                            <DropdownMenuItem onClick={() => handleViewCampaign(campaign.id)} className="rounded-lg py-3 hover:bg-white/5 cursor-pointer">
                                                                <Eye className="w-4 h-4 mr-3 text-ch-orange" /> Inspecionar Ativos
                                                            </DropdownMenuItem>
                                                            <DropdownMenuItem onClick={() => navigate(`/campanhas/${campaign.id}/editar`)} className="rounded-lg py-3 hover:bg-white/5 cursor-pointer">
                                                                <ListChecks className="w-4 h-4 mr-3 text-blue-400" /> Configurar Criativos
                                                            </DropdownMenuItem>
                                                            <DropdownMenuItem onClick={() => handleRunDiagnosis(campaign.id)} className="rounded-lg py-3 hover:bg-white/5 cursor-pointer">
                                                                <Sparkles className="w-4 h-4 mr-3 text-ch-orange" /> Diagnóstico IA
                                                            </DropdownMenuItem>
                                                            <div className="h-px bg-white/5 my-2" />
                                                            {campaign.status === 'active' ? (
                                                                <DropdownMenuItem className="rounded-lg py-3 text-rose-500 focus:text-rose-400 hover:bg-rose-500/5 cursor-pointer" onClick={async () => {
                                                                    await executeAction(campaign.id, 'pause');
                                                                    toast.success('Suspensão do motor de campanha executada');
                                                                    queryClient.invalidateQueries({ queryKey: ['campaigns'] });
                                                                }}>
                                                                    <Pause className="w-4 h-4 mr-3" /> Suspender Operação
                                                                </DropdownMenuItem>
                                                            ) : (
                                                                <DropdownMenuItem className="rounded-lg py-3 text-emerald-500 focus:text-emerald-400 hover:bg-emerald-500/5 cursor-pointer" onClick={async () => {
                                                                    await executeAction(campaign.id, 'activate');
                                                                    toast.success('Motor de campanha reativado');
                                                                    queryClient.invalidateQueries({ queryKey: ['campaigns'] });
                                                                }}>
                                                                    <Play className="w-4 h-4 mr-3" /> Reativar Operação
                                                                </DropdownMenuItem>
                                                            )}
                                                        </DropdownMenuContent>
                                                    </DropdownMenu>
                                                </div>
                                            </TableCell>
                                        </TableRow>
                                    );
                                })}
                            </TableBody>
                        </Table>
                    </div>
                ) : (
                    <div className="py-40 text-center flex flex-col items-center glass-premium border-none">
                        <div className="w-24 h-24 bg-ch-orange/5 border border-ch-orange/10 rounded-[2.5rem] flex items-center justify-center mb-8">
                            <Megaphone className="w-10 h-10 text-ch-orange animate-pulse" />
                        </div>
                        <h2 className="text-2xl font-black text-ch-white uppercase tracking-tight mb-2">Vácuo de Operações</h2>
                        <p className="text-ch-text-muted max-w-sm mx-auto font-medium mb-10 leading-relaxed uppercase text-[10px] tracking-widest">
                            Nenhum ativo detectado sob as condições atuais de filtragem. Sincronize com o Meta para expandir.
                        </p>
                        <Button
                            variant="outline"
                            className="bg-ch-dark-gray/40 border-white/5 hover:bg-white/5 text-ch-orange font-black uppercase text-[11px] tracking-widest h-14 px-10 rounded-2xl transition-all"
                            onClick={() => { setSearch(''); setStatusFilter('all'); }}
                        >
                            Resetar Parâmetros Globais
                        </Button>
                    </div>
                )}

                {/* Ledger Navigation */}
                {!isLoading && totalPages > 1 && (
                    <div className="px-8 py-8 border-t border-white/5 flex items-center justify-between bg-white/[0.01]">
                        <p className="text-[10px] font-black text-ch-text-dimmed uppercase tracking-wide">
                            Exibindo Lote Ativo {page * PAGE_SIZE + 1} — {Math.min((page + 1) * PAGE_SIZE, total)} / {total} TOTAL
                        </p>
                        <div className="flex items-center gap-4">
                            <Button
                                variant="outline"
                                size="icon"
                                onClick={() => setPage(p => Math.max(0, p - 1))}
                                disabled={page === 0}
                                className="h-12 w-12 bg-white/5 border-white/5 hover:bg-white/10 rounded-2xl transition-all disabled:opacity-20"
                            >
                                <ChevronLeft className="w-5 h-5" />
                            </Button>
                            <div className="flex items-center px-6 py-3 bg-white/5 rounded-2xl border border-white/5">
                                <span className="text-xs font-black text-ch-white uppercase">Bloco {page + 1} <span className="text-ch-text-dimmed mx-2 opacity-30">|</span> {totalPages}</span>
                            </div>
                            <Button
                                variant="outline"
                                size="icon"
                                onClick={() => setPage(p => Math.min(totalPages - 1, p + 1))}
                                disabled={page >= totalPages - 1}
                                className="h-12 w-12 bg-white/5 border-white/5 hover:bg-white/10 rounded-2xl transition-all disabled:opacity-20"
                            >
                                <ChevronRight className="w-5 h-5" />
                            </Button>
                        </div>
                    </div>
                )}
            </motion.div>

            <AiDiagnosisModal
                isOpen={isAiModalOpen}
                onClose={() => setIsAiModalOpen(false)}
                data={aiData}
                isLoading={isAiLoading}
                onReanalyze={() => selectedCampaignId && handleRunDiagnosis(selectedCampaignId)}
                title="Diagnóstico de Campanha"
            />
        </motion.div>
    );
}

import { AiDiagnosisModal } from '@/components/ai/AiDiagnosisModal';

import { useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { Button } from '@/components/ui/button';
import {
    ArrowLeft,
    Image,
    Play,
    Loader2,
    Eye,
    MousePointerClick,
    TrendingUp,
    DollarSign,
    Target,
    BarChart3,
    Film,
    FileImage,
    ExternalLink,
    AlertTriangle,
    CheckCircle,
    Clock,
    MoreVertical,
    Pause,
    Zap,
    Sparkles,
    ShieldCheck,
    Type,
    Link as LinkIcon,
    Award,
    Trash2,
    Activity,
    ChevronRight,
    ArrowRight
} from 'lucide-react';
import {
    DropdownMenu,
    DropdownMenuContent,
    DropdownMenuItem,
    DropdownMenuLabel,
    DropdownMenuSeparator,
    DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import {
    Dialog,
    DialogContent,
    DialogHeader,
    DialogTitle,
} from "@/components/ui/dialog";
import { format } from 'date-fns';
import { ptBR } from 'date-fns/locale';
import { toast } from 'sonner';
import { motion, AnimatePresence } from 'framer-motion';

const formatCurrency = (value: number) => {
    return new Intl.NumberFormat('pt-BR', {
        style: 'currency',
        currency: 'BRL',
    }).format(value);
};

const formatNumber = (value: number) => {
    if (value >= 1000000) return `${(value / 1000000).toFixed(2)}M`;
    if (value >= 1000) return `${(value / 1000).toFixed(2)}K`;
    return value.toLocaleString('pt-BR');
};

const formatPercent = (value: number) => {
    return `${value.toFixed(2)}%`;
};

const container = {
    hidden: { opacity: 0 },
    show: {
        opacity: 1,
        transition: {
            staggerChildren: 0.05
        }
    }
};

const item = {
    hidden: { opacity: 0, y: 15 },
    show: { opacity: 1, y: 0 }
};

export default function CriativoDetalhe() {
    const { id } = useParams<{ id: string }>();
    const navigate = useNavigate();
    const queryClient = useQueryClient();

    const [previewContent, setPreviewContent] = useState<string | null>(null);
    const [isPreviewOpen, setIsPreviewOpen] = useState(false);

    const { data: creative, isLoading } = useQuery({
        queryKey: ['creative', id],
        queryFn: async () => {
            if (!id) throw new Error('No creative ID');

            const { data, error } = await supabase
                .from('creatives')
                .select('*, campaigns(name, status)')
                .eq('id', id)
                .single();

            if (error) throw error;
            return data;
        },
        enabled: !!id,
    });

    const { data: audits } = useQuery({
        queryKey: ['creative-audits', id],
        queryFn: async () => {
            if (!id) throw new Error('No creative ID');

            const { data, error } = await supabase
                .from('audits')
                .select('*')
                .eq('creative_id', id)
                .order('created_at', { ascending: false })
                .limit(5);

            if (error) throw error;
            return data || [];
        },
        enabled: !!id,
    });

    const adAction = useMutation({
        mutationFn: async ({ action }: { action: string }) => {
            const { data: { session } } = await supabase.auth.getSession();
            if (!session) throw new Error('No session');

            const response = await fetch(`${import.meta.env.VITE_SUPABASE_URL}/functions/v1/meta-ad-action`, {
                method: 'POST',
                headers: {
                    'Authorization': `Bearer ${session.access_token}`,
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify({
                    creative_id: id,
                    action,
                }),
            });

            if (!response.ok) {
                const error = await response.json();
                throw new Error(error.error || 'Failed to perform action');
            }

            return response.json();
        },
        onSuccess: (data, variables) => {
            if (variables.action === 'preview' && data.preview_content) {
                setPreviewContent(data.preview_content);
                setIsPreviewOpen(true);
            } else {
                toast.success(`Ação ${variables.action} realizada com sucesso`);
                queryClient.invalidateQueries({ queryKey: ['creative', id] });
            }
        },
        onError: (error) => {
            toast.error(`Erro: ${error.message}`);
        }
    });

    const getTypeIcon = (type: string | null) => {
        switch (type) {
            case 'video':
                return <Film className="w-5 h-5" />;
            case 'image':
                return <FileImage className="w-5 h-5" />;
            default:
                return <Image className="w-5 h-5" />;
        }
    };

    const getTypeBadge = (type: string | null) => {
        const config: Record<string, { label: string, color: string, icon: any }> = {
            video: { label: 'Vídeo Performance', color: 'purple-500', icon: Film },
            image: { label: 'Imagem Estática', color: 'blue-500', icon: FileImage },
            carousel: { label: 'Carrossel', color: 'emerald-500', icon: Target },
        };
        const cfg = config[type || ''] || { label: 'Anúncio', color: 'ch-text-dimmed', icon: Image };
        const Icon = cfg.icon;
        return (
            <span className={`inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest bg-${cfg.color}/10 text-${cfg.color} border border-${cfg.color}/20 shadow-sm`}>
                <Icon className="w-3.5 h-3.5" />
                {cfg.label}
            </span>
        );
    };

    const getAuditStatusBadge = (status: string) => {
        const config: Record<string, { label: string, color: string, icon: any }> = {
            approved: { label: 'Aprovado', color: 'emerald-500', icon: CheckCircle },
            rejected: { label: 'Rejeitado', color: 'rose-500', icon: AlertTriangle },
            pending: { label: 'Análise Pendente', color: 'amber-500', icon: Clock },
        };
        const cfg = config[status] || config.pending;
        const Icon = cfg.icon;
        return (
            <span className={`text-[9px] font-black uppercase tracking-widest px-2.5 py-1 rounded-full flex items-center gap-1.5 bg-${cfg.color}/10 text-${cfg.color} border border-${cfg.color}/20`}>
                <Icon className="w-3 h-3" />
                {cfg.label}
            </span>
        );
    };

    if (isLoading || !creative) {
        return (
            <div className="p-6 flex flex-col items-center justify-center min-h-[500px] gap-4">
                <Loader2 className="w-10 h-10 animate-spin text-ch-orange opacity-40" />
                <p className="text-[10px] font-black text-ch-text-dimmed uppercase tracking-widest">Escaneando ativos visuais...</p>
            </div>
        );
    }

    const ctr = creative.ctr ? Number(creative.ctr) : 0;
    const cpc = creative.cpc ? Number(creative.cpc) : 0;

    return (
        <motion.div
            initial="hidden"
            animate="show"
            variants={container}
            className="p-6 space-y-8"
        >
            {/* Header */}
            <motion.div variants={item} className="flex flex-col md:flex-row md:items-center justify-between gap-6">
                <div className="flex items-center gap-5">
                    <Button
                        variant="outline"
                        size="icon"
                        onClick={() => navigate('/criativos')}
                        className="h-12 w-12 bg-ch-dark-gray/40 border-white/5 hover:bg-ch-orange/10 hover:text-ch-orange transition-all duration-300 rounded-2xl group"
                    >
                        <ArrowLeft className="w-5 h-5 group-hover:-translate-x-1 transition-transform" />
                    </Button>
                    <div>
                        <div className="flex items-center gap-3 mb-1">
                            <Sparkles className="w-4 h-4 text-ch-orange" />
                            <span className="text-[10px] font-black text-ch-orange uppercase tracking-[0.2em]">Visão do Ativo IA</span>
                        </div>
                        <h1 className="text-3xl font-black text-ch-white tracking-tight uppercase italic">{creative.name}</h1>
                        <div className="flex items-center gap-3 mt-1.5">
                            <span className="text-[11px] font-bold text-ch-text-dimmed">ID: {creative.external_id}</span>
                            <span className="w-1 h-1 rounded-full bg-white/10" />
                            <span className="text-[11px] font-black text-ch-text-muted uppercase tracking-wider">{creative.campaigns?.name || 'Vago'}</span>
                        </div>
                    </div>
                </div>

                <div className="flex items-center gap-3">
                    <div className="flex items-center gap-2 px-4 py-2 bg-emerald-500/5 border border-emerald-500/10 rounded-xl mr-2">
                        <ShieldCheck className="w-4 h-4 text-emerald-500" />
                        <span className="text-[10px] font-black text-emerald-500 uppercase tracking-widest">Seguro para Escala</span>
                    </div>

                    <DropdownMenu>
                        <DropdownMenuTrigger asChild>
                            <Button className="bg-ch-white hover:bg-ch-orange text-ch-black font-black uppercase tracking-widest rounded-xl transition-all h-12 px-6 shadow-xl group">
                                Controle <Zap className="ml-2 h-4 w-4 group-hover:animate-pulse" />
                            </Button>
                        </DropdownMenuTrigger>
                        <DropdownMenuContent align="end" className="bg-ch-black-soft border-white/10 w-56">
                            <DropdownMenuLabel className="text-[10px] font-black uppercase tracking-widest text-ch-text-dimmed">Gestão de Status</DropdownMenuLabel>
                            {creative.status === 'active' ? (
                                <DropdownMenuItem onClick={() => adAction.mutate({ action: 'pause' })} className="py-3 cursor-pointer">
                                    <Pause className="mr-3 h-4 w-4 text-amber-500" /> <span className="font-bold">Interromper Veiculação</span>
                                </DropdownMenuItem>
                            ) : (
                                <DropdownMenuItem onClick={() => adAction.mutate({ action: 'activate' })} className="py-3 cursor-pointer">
                                    <Play className="mr-3 h-4 w-4 text-emerald-500" /> <span className="font-bold">Retomar Veiculação</span>
                                </DropdownMenuItem>
                            )}
                            <DropdownMenuSeparator className="bg-white/5" />
                            <DropdownMenuItem onClick={() => adAction.mutate({ action: 'preview' })} className="py-3 cursor-pointer">
                                <Eye className="mr-3 h-4 w-4 text-blue-400" /> Gerar Preview Real
                            </DropdownMenuItem>
                            <DropdownMenuSeparator className="bg-white/5" />
                            <DropdownMenuItem className="py-3 text-rose-500 opacity-50 cursor-not-allowed">
                                <Trash2 className="mr-3 h-4 w-4" /> Remover Ativo
                            </DropdownMenuItem>
                        </DropdownMenuContent>
                    </DropdownMenu>

                    {creative.video_url && (
                        <Button
                            variant="outline"
                            onClick={() => window.open(creative.video_url!, '_blank')}
                            className="bg-ch-dark-gray/40 border-white/5 h-12 px-6 rounded-xl font-black uppercase text-[10px] tracking-widest"
                        >
                            <ExternalLink className="w-4 h-4 mr-2" />
                            Origem
                        </Button>
                    )}
                </div>
            </motion.div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                {/* Visual Preview Side */}
                <motion.div variants={item} className="lg:col-span-1 space-y-6">
                    <div className="glass-premium rounded-[2.5rem] overflow-hidden shadow-2xl group border-white/10">
                        <div className="aspect-[4/5] bg-ch-black relative overflow-hidden">
                            {creative.image_url ? (
                                <img
                                    src={creative.image_url}
                                    alt={creative.name}
                                    className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-[2s] ease-out shadow-inner"
                                />
                            ) : (
                                <div className="w-full h-full flex flex-col items-center justify-center gap-4 text-ch-text-dimmed bg-white/[0.02]">
                                    {getTypeIcon(creative.type)}
                                    <span className="text-[10px] font-black uppercase tracking-widest opacity-40">Ativo Sem Preview</span>
                                </div>
                            )}

                            {creative.type === 'video' && (
                                <div className="absolute inset-0 flex items-center justify-center bg-black/40 group-hover:bg-black/20 transition-colors animate-pulse-slow">
                                    <div className="w-20 h-20 rounded-full bg-white/10 backdrop-blur-md border border-white/20 flex items-center justify-center group-hover:scale-110 transition-transform">
                                        <Play className="w-10 h-10 text-white fill-white" />
                                    </div>
                                </div>
                            )}

                            <div className="absolute top-6 right-6">
                                {getTypeBadge(creative.type)}
                            </div>
                        </div>

                        <div className="p-8 space-y-8 relative bg-ch-black/40 backdrop-blur-3xl">
                            {creative.headline && (
                                <div className="relative">
                                    <div className="flex items-center gap-2 mb-3">
                                        <Type className="w-3 h-3 text-ch-orange" />
                                        <span className="text-[9px] font-black text-ch-text-muted uppercase tracking-[0.2em]">Chamada de Ação</span>
                                    </div>
                                    <p className="text-xl font-black text-ch-white leading-tight uppercase italic">{creative.headline}</p>
                                </div>
                            )}

                            {creative.text && (
                                <div className="relative">
                                    <div className="flex items-center gap-2 mb-3">
                                        <Activity className="w-3 h-3 text-ch-orange" />
                                        <span className="text-[9px] font-black text-ch-text-muted uppercase tracking-[0.2em]">Copywriting Principal</span>
                                    </div>
                                    <p className="text-sm font-medium text-ch-text-dimmed leading-relaxed bg-white/[0.02] p-4 rounded-2xl border border-white/5">{creative.text}</p>
                                </div>
                            )}

                            <div className="flex items-center justify-between pt-4 border-t border-white/5">
                                <div className="flex items-center gap-3">
                                    <div className="w-10 h-10 bg-ch-white rounded-full flex items-center justify-center shadow-lg">
                                        <Target className="w-5 h-5 text-ch-black" />
                                    </div>
                                    <div>
                                        <p className="text-[10px] font-black text-ch-text-dimmed uppercase tracking-widest mb-1.5">Investimento Total</p>
                                        <p className="text-xl font-black text-ch-white italic tabular-nums">
                                            R${(creative as any).spend?.toFixed(2) || '0,00'}
                                        </p></div>
                                </div>
                                <Button variant="ghost" className="text-ch-orange hover:bg-ch-orange/10 hover:text-ch-orange font-black uppercase text-[10px] tracking-widest px-4 rounded-xl">
                                    Análise IA <ChevronRight className="ml-1 w-4 h-4" />
                                </Button>
                            </div>
                        </div>
                    </div>
                </motion.div>

                {/* Intelligence & Audit Side */}
                <div className="lg:col-span-2 space-y-8">
                    {/* Key Metrics Grid */}
                    <div className="grid grid-cols-2 lg:grid-cols-3 gap-4">
                        {[
                            { label: 'Gasto no Ativo', value: formatCurrency(creative.spend || 0), icon: DollarSign, color: 'emerald-400' },
                            { label: 'Alcance Global', value: formatNumber(creative.impressions || 0), icon: Eye, color: 'blue-400' },
                            { label: 'Cliques Únicos', value: formatNumber(creative.clicks || 0), icon: MousePointerClick, color: 'indigo-400' },
                            { label: 'CTR do Ativo', value: formatPercent(ctr), icon: TrendingUp, color: 'ch-orange' },
                            { label: 'Custo p/ Clique', value: formatCurrency(cpc), icon: Target, color: 'amber-400' },
                            { label: 'Conversões IA', value: formatNumber(creative.conversions || 0), icon: Award, color: 'rose-400' },
                        ].map((metric) => (
                            <motion.div key={metric.label} variants={item} whileHover={{ y: -3 }} className="glass-card rounded-3xl p-6 border-white/5 shadow-xl group">
                                <div className="flex items-center gap-3 mb-4">
                                    <div className={`p-2 bg-${metric.color}/10 rounded-xl`}>
                                        <metric.icon className={`w-4 h-4 text-${metric.color}`} />
                                    </div>
                                    <span className="text-[10px] font-black text-ch-text-muted uppercase tracking-widest">{metric.label}</span>
                                </div>
                                <p className="text-2xl font-black text-ch-white tracking-tighter tabular-nums group-hover:text-ch-orange transition-colors">{metric.value}</p>
                            </motion.div>
                        ))}
                    </div>

                    {/* Metadata & Technical Info */}
                    <motion.div variants={item} className="glass rounded-[2rem] p-8 border-white/5 shadow-2xl relative overflow-hidden">
                        <div className="absolute bottom-0 right-0 p-12 opacity-[0.02] pointer-events-none">
                            <BarChart3 className="w-48 h-48 text-ch-white" />
                        </div>
                        <h3 className="text-lg font-black text-ch-white uppercase tracking-tight mb-8 flex items-center gap-3">
                            <div className="w-1.5 h-6 bg-ch-orange rounded-full" /> Parâmetros Técnicos
                        </h3>
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-10">
                            <div className="space-y-6">
                                <div>
                                    <p className="text-[9px] font-black text-ch-text-muted uppercase tracking-[0.2em] mb-2">Plataforma</p>
                                    <p className="text-ch-white font-bold uppercase flex items-center gap-2">
                                        <div className="w-2 h-2 rounded-full bg-blue-500 animate-pulse" /> {creative.platform || 'Facebook Ads'}
                                    </p>
                                </div>
                                <div>
                                    <p className="text-ch-white font-bold uppercase">{creative.creative_format || 'Post Square 1:1'}</p>
                                </div>
                            </div>
                            <div className="space-y-6">
                                <div>
                                    <p className="text-[10px] font-black text-ch-text-dimmed uppercase tracking-widest mb-1.5">Ranking Qualidade</p>
                                    <p className="text-sm font-black text-ch-orange uppercase italic">
                                        {(creative as any).quality_ranking || 'NORMAL'}
                                    </p>
                                </div>
                                <div>
                                    <p className="text-[9px] font-black text-ch-text-muted uppercase tracking-[0.2em] mb-2">Status do Token</p>
                                    <p className="text-ch-white font-bold uppercase flex items-center gap-2">
                                        Sincronizado <CheckCircle className="w-3 h-3 text-emerald-500" />
                                    </p>
                                </div>
                            </div>
                            <div className="space-y-6">
                                <div>
                                    <p className="text-[9px] font-black text-ch-text-muted uppercase tracking-[0.2em] mb-2">URL Final</p>
                                    <a href={creative.link_url} target="_blank" rel="noopener noreferrer" className="text-ch-orange font-bold hover:underline flex items-center gap-1.5 text-xs truncate">
                                        {creative.link_url ? 'Abrir Destino' : '-'} <LinkIcon className="w-3 h-3" />
                                    </a>
                                </div>
                                <div>
                                    <p className="text-[9px] font-black text-ch-text-muted uppercase tracking-[0.2em] mb-2">Última Auditoria</p>
                                    <p className="text-ch-white font-bold uppercase">{creative.last_audit_at ? format(new Date(creative.last_audit_at), "dd/MM/yyyy") : 'Análise Pendente'}</p>
                                </div>
                            </div>
                        </div>
                    </motion.div>

                    {/* AI Audits History */}
                    {audits && audits.length > 0 && (
                        <motion.div variants={item} className="glass rounded-[2rem] overflow-hidden border-white/5 shadow-2xl">
                            <div className="p-8 border-b border-white/5 flex items-center justify-between bg-white/[0.01]">
                                <div className="flex items-center gap-3">
                                    <div className="p-2 bg-ch-orange/10 rounded-xl">
                                        <ShieldCheck className="w-5 h-5 text-ch-orange" />
                                    </div>
                                    <h2 className="text-lg font-black text-ch-white uppercase tracking-tight">Histórico de Auditoria IA</h2>
                                </div>
                            </div>
                            <div className="divide-y divide-white/5">
                                {audits.map((audit: any) => (
                                    <div key={audit.id} className="p-8 flex flex-col md:flex-row md:items-center justify-between hover:bg-white/[0.02] transition-all group">
                                        <div className="flex items-center gap-6">
                                            <div className="w-14 h-14 bg-ch-black border border-white/10 rounded-2xl flex items-center justify-center group-hover:bg-ch-orange transition-all duration-500 shadow-xl">
                                                <Award className="w-6 h-6 text-ch-text-muted group-hover:text-ch-black" />
                                            </div>
                                            <div>
                                                <p className="font-black text-ch-white uppercase tracking-tight group-hover:text-ch-orange transition-colors">
                                                    {audit.audit_type?.replace(/_/g, ' ') || 'Verificação de Política'}
                                                </p>
                                                <p className="text-xs text-ch-text-muted font-bold mt-1 uppercase tracking-widest flex items-center gap-2">
                                                    <Clock className="w-3 h-3" /> {format(new Date(audit.created_at), "dd/MM/yyyy HH:mm", { locale: ptBR })}
                                                </p>
                                            </div>
                                        </div>
                                        <div className="flex items-center gap-10 mt-6 md:mt-0">
                                            {audit.score != null && (
                                                <div className="text-right">
                                                    <p className="text-[9px] font-black text-ch-text-dimmed uppercase tracking-[0.2em] mb-1">Score IA</p>
                                                    <div className="flex items-center gap-2">
                                                        <div className="w-16 h-1.5 bg-white/5 rounded-full overflow-hidden">
                                                            <div className="h-full bg-ch-orange rounded-full" style={{ width: `${audit.score}%` }} />
                                                        </div>
                                                        <span className="text-sm font-black text-ch-white tabular-nums">{audit.score}%</span>
                                                    </div>
                                                </div>
                                            )}
                                            {getAuditStatusBadge(audit.status)}
                                            <ChevronRight className="w-5 h-5 text-ch-text-dimmed group-hover:text-ch-orange group-hover:translate-x-1 transition-all" />
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </motion.div>
                    )}
                </div>
            </div>

            {/* Preview Dialog */}
            <AnimatePresence>
                {isPreviewOpen && (
                    <Dialog open={isPreviewOpen} onOpenChange={setIsPreviewOpen}>
                        <DialogContent className="max-w-4xl h-[85vh] flex flex-col bg-ch-black-soft border-white/10 p-0 overflow-hidden rounded-[2.5rem] shadow-[0_0_100px_rgba(242,106,33,0.15)]">
                            <div className="p-6 border-b border-white/5 flex items-center justify-between bg-ch-black-soft">
                                <div className="flex items-center gap-3">
                                    <Eye className="w-5 h-5 text-ch-orange" />
                                    <h2 className="text-lg font-black text-ch-white uppercase tracking-tight italic">Renderização em Tempo Real</h2>
                                </div>
                                <Button variant="ghost" className="text-ch-text-muted hover:text-ch-white" onClick={() => setIsPreviewOpen(false)}>
                                    Fechar
                                </Button>
                            </div>
                            <div className="flex-1 bg-[#f0f2f5] overflow-auto p-8 flex justify-center items-start">
                                {previewContent ? (
                                    <div className="w-full max-w-md shadow-2xl rounded-xl overflow-hidden animate-in fade-in zoom-in duration-500">
                                        <div dangerouslySetInnerHTML={{ __html: previewContent }} className="bg-white" />
                                    </div>
                                ) : (
                                    <div className="flex flex-col items-center justify-center h-full gap-4 text-ch-black">
                                        <Loader2 className="w-10 h-10 animate-spin text-ch-orange" />
                                        <span className="text-[10px] font-black uppercase tracking-widest opacity-40">Consultando Meta API...</span>
                                    </div>
                                )}
                            </div>
                        </DialogContent>
                    </Dialog>
                )}
            </AnimatePresence>
        </motion.div>
    );
}

import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '@/contexts/AuthContext';
import { useCreatives } from '@/hooks/useCreatives';
import { TagList } from '@/components/tags/TagBadge';
import { TagSelector } from '@/components/tags/TagSelector';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from '@/components/ui/select';
import {
    Image as ImageIcon,
    Search,
    Filter,
    Grid3X3,
    List,
    Loader2,
    Play,
    FileImage,
    Film,
    Eye,
    MousePointerClick,
    TrendingUp,
    ChevronLeft,
    ChevronRight,
    LayoutGrid,
    CheckCircle2,
    Sparkles,
    Zap,
    Target,
    BarChart3,
    Award,
    Activity,
    ShieldCheck,
    Briefcase
} from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';

const PAGE_SIZE = 12;

const formatNumber = (value: number) => {
    if (value >= 1000000) return `${(value / 1000000).toFixed(1)}M`;
    if (value >= 1000) return `${(value / 1000).toFixed(1)}K`;
    return value.toLocaleString('pt-BR');
};

const container = {
    hidden: { opacity: 0 },
    show: {
        opacity: 1,
        transition: {
            staggerChildren: 0.05
        }
    }
};

const item = {
    hidden: { opacity: 0, y: 15 },
    show: { opacity: 1, y: 0 }
};

export default function Criativos() {
    const navigate = useNavigate();
    const { user } = useAuth();
    const [search, setSearch] = useState('');
    const [typeFilter, setTypeFilter] = useState<string>('all');
    const [viewMode, setViewMode] = useState<'grid' | 'list'>('grid');
    const [page, setPage] = useState(0);

    // AI Diagnosis State
    const [isAiModalOpen, setIsAiModalOpen] = useState(false);
    const [isAiLoading, setIsAiLoading] = useState(false);
    const [selectedCreativeId, setSelectedCreativeId] = useState<string | null>(null);
    const [aiData, setAiData] = useState<any>(null);

    const handleRunDiagnosis = async (id: string) => {
        setSelectedCreativeId(id);
        setIsAiModalOpen(true);
        setIsAiLoading(true);
        setAiData(null);

        try {
            const { data: { session } } = await supabase.auth.getSession();
            if (!session) throw new Error('No session');

            const response = await fetch(`${import.meta.env.VITE_SUPABASE_URL}/functions/v1/audit-creative`, {
                method: 'POST',
                headers: {
                    'Authorization': `Bearer ${session.access_token}`,
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify({ creative_id: id }),
            });

            if (!response.ok) throw new Error('Falha na análise');
            const data = await response.json();
            // Map legacy response format if needed, or ensure backend sends consistent structure
            // audit-creative returns { audit_id, status, ... } but we might need to fetch the full audit record or return it in the response
            // Let's assume for now we might need to fetch the full audit record if the response is slim
            // Actually, audit-creative response seems to have enough, but let's check if it has the 'ai_analysis' object fully.
            // Looking at the edge function, it returns { has_ai_analysis: boolean ... }. It doesn't return the full AI object in the root response.
            // We might need to fetch the audit record from the DB using the audit_id returned.

            if (data.audit_id) {
                const { data: auditRecord, error } = await supabase
                    .from('audits')
                    .select('*')
                    .eq('id', data.audit_id)
                    .single();
                if (auditRecord) setAiData(auditRecord);
                else setAiData(data); // Fallback
            } else {
                setAiData(data);
            }

        } catch (error) {
            console.error(error);
            import('sonner').then(({ toast }) => toast.error('Erro ao executar diagnóstico IA'));
            setIsAiModalOpen(false);
        } finally {
            setIsAiLoading(false);
        }
    };

    const companyId = user?.company?.id;

    const { data, isLoading } = useCreatives({
        search: search || undefined,
        type: typeFilter !== 'all' ? typeFilter : undefined,
        limit: PAGE_SIZE,
        offset: page * PAGE_SIZE,
    });

    const creatives = data?.creatives || [];
    const total = data?.total || 0;
    const totalPages = Math.ceil(total / PAGE_SIZE);

    const getTypeConfig = (type: string | null) => {
        const config: Record<string, { label: string, color: string, icon: any }> = {
            video: { label: 'Motion Asset', color: 'indigo-500', icon: Film },
            image: { label: 'Static Visual', color: 'blue-500', icon: FileImage },
            carousel: { label: 'Multi-Asset', color: 'emerald-500', icon: Grid3X3 },
        };
        return config[type || ''] || { label: 'Other Asset', color: 'ch-text-dimmed', icon: ImageIcon };
    };

    const handleViewCreative = (creativeId: string) => {
        navigate(`/criativos/${creativeId}`);
    };

    return (
        <motion.div
            initial="hidden"
            animate="show"
            variants={container}
            className="p-6 space-y-10"
        >
            {/* Ultra Header */}
            <motion.div variants={item} className="flex flex-col md:flex-row md:items-center justify-between gap-8">
                <div>
                    <div className="flex items-center gap-3 mb-1">
                        <Sparkles className="w-4 h-4 text-ch-orange" />
                        <span className="text-[10px] font-bold text-ch-orange uppercase tracking-[.2em]">Inteligência Criativa</span>
                    </div>
                    <h1 className="text-3xl font-bold text-ch-white tracking-tight uppercase">Repositório de Ativos Digitais</h1>
                    <p className="text-ch-text-muted font-medium mt-1">Orquestração e análise de alto impacto para seus ativos criativos.</p>
                </div>
            </motion.div>

            {/* Quick Insights Grid */}
            <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
                {[
                    { label: 'Biblioteca', value: total, icon: LayoutGrid, color: 'ch-orange' },
                    { label: 'Vídeo / Motion', value: creatives.filter(c => c.type === 'video').length, icon: Film, color: 'indigo-400' },
                    { label: 'Estáticos', value: creatives.filter(c => c.type === 'image').length, icon: FileImage, color: 'blue-400' },
                    { label: 'Impressões Totais', value: formatNumber(creatives.reduce((acc, c) => acc + (c.impressions || 0), 0)), icon: TrendingUp, color: 'emerald-400' }
                ].map((stat) => (
                    <motion.div key={stat.label} variants={item} whileHover={{ y: -3 }} className="glass-card rounded-[2rem] p-6 border-white/5 shadow-xl group">
                        <div className="flex items-center gap-4 mb-4">
                            <div className={`p-2.5 bg-${stat.color}/10 rounded-xl`}>
                                <stat.icon className={`w-5 h-5 text-${stat.color}`} />
                            </div>
                            <span className="text-[10px] font-bold text-ch-text-muted uppercase tracking-widest leading-none">{stat.label}</span>
                        </div>
                        <p className="text-2xl font-bold text-ch-white tracking-tighter tabular-nums group-hover:text-ch-orange transition-colors">{stat.value}</p>
                    </motion.div>
                ))}
            </div>

            {/* Controls Bar */}
            <motion.div variants={item} className="flex flex-col md:flex-row items-center gap-4 bg-white/[0.02] border border-white/5 p-4 rounded-[1.5rem] backdrop-blur-sm shadow-xl">
                <div className="relative flex-1 w-full">
                    <Search className="absolute left-6 top-1/2 -translate-y-1/2 w-4 h-4 text-ch-text-dimmed" />
                    <Input
                        placeholder="LOCALIZAR ATIVO POR NOME, ID OU CAMPANHAassociate..."
                        value={search}
                        onChange={(e) => {
                            setSearch(e.target.value);
                            setPage(0);
                        }}
                        className="pl-14 bg-transparent border-none text-[10px] font-bold uppercase tracking-[.1em] focus-visible:ring-0 placeholder:opacity-20 h-12"
                    />
                </div>

                <div className="flex items-center gap-4 w-full md:w-auto px-2">
                    <Select
                        value={typeFilter}
                        onValueChange={(v) => {
                            setTypeFilter(v);
                            setPage(0);
                        }}
                    >
                        <SelectTrigger className="flex-1 md:w-56 bg-ch-dark-gray/40 border-white/5 h-12 rounded-xl text-[10px] font-black uppercase tracking-widest">
                            <Filter className="w-4 h-4 mr-2 text-ch-orange" />
                            <SelectValue placeholder="Formato de Mídia" />
                        </SelectTrigger>
                        <SelectContent className="bg-ch-black-soft border-white/10 font-black uppercase text-[10px] tracking-widest">
                            <SelectItem value="all">Sincronizar Tudo</SelectItem>
                            <SelectItem value="image" className="text-blue-400">Estáticos</SelectItem>
                            <SelectItem value="video" className="text-indigo-400">Motion Art</SelectItem>
                            <SelectItem value="carousel" className="text-emerald-400">Multi-Asset</SelectItem>
                        </SelectContent>
                    </Select>

                    <div className="flex p-1 bg-ch-dark-gray/40 border border-white/10 rounded-xl h-12 shadow-inner">
                        <Button
                            variant="ghost"
                            size="icon"
                            onClick={() => setViewMode('grid')}
                            className={`h-full w-10 rounded-lg transition-all ${viewMode === 'grid' ? 'bg-ch-white text-ch-black' : 'text-ch-text-dimmed hover:text-white'}`}
                        >
                            <Grid3X3 className="w-4 h-4" />
                        </Button>
                        <Button
                            variant="ghost"
                            size="icon"
                            onClick={() => setViewMode('list')}
                            className={`h-full w-10 rounded-lg transition-all ${viewMode === 'list' ? 'bg-ch-white text-ch-black' : 'text-ch-text-dimmed hover:text-white'}`}
                        >
                            <List className="w-4 h-4" />
                        </Button>
                    </div>
                </div>
            </motion.div>

            {/* Dynamic Gallery */}
            <AnimatePresence mode="wait">
                {isLoading ? (
                    <motion.div
                        key="loading"
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        exit={{ opacity: 0 }}
                        className="py-32 flex flex-col items-center justify-center gap-6"
                    >
                        <div className="relative">
                            <RefreshCw className="w-16 h-16 animate-spin text-ch-orange opacity-20" />
                            <Zap className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-6 h-6 text-ch-orange" />
                        </div>
                        <div className="text-center">
                            <p className="text-[10px] font-bold uppercase tracking-[.2em] text-ch-orange mb-2">Analisando Repositório</p>
                            <p className="text-ch-text-dimmed font-medium">Processando metadados de mídia do Meta Business...</p>
                        </div>
                    </motion.div>
                ) : creatives.length > 0 ? (
                    <motion.div
                        key={viewMode}
                        variants={container}
                        initial="hidden"
                        animate="show"
                        exit="hidden"
                        className="space-y-8"
                    >
                        {viewMode === 'grid' ? (
                            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-8">
                                {creatives.map((creative) => {
                                    const config = getTypeConfig(creative.type);
                                    const Icon = config.icon;
                                    const typeColor = creative.type === 'video' ? { bg: 'bg-indigo-500/10', text: 'text-indigo-400', border: 'border-indigo-500/20' } :
                                        creative.type === 'image' ? { bg: 'bg-blue-500/10', text: 'text-blue-400', border: 'border-blue-500/20' } :
                                            creative.type === 'carousel' ? { bg: 'bg-emerald-500/10', text: 'text-emerald-400', border: 'border-emerald-500/20' } :
                                                { bg: 'bg-white/5', text: 'text-ch-text-dimmed', border: 'border-white/10' };

                                    return (
                                        <motion.div
                                            key={creative.id}
                                            variants={item}
                                            whileHover={{ y: -8 }}
                                            className="glass-card rounded-[2.5rem] overflow-hidden cursor-pointer group border border-white/5 bg-white/[0.01] hover:bg-white/[0.03] transition-all flex flex-col shadow-2xl hover:shadow-ch-orange/10"
                                            onClick={() => handleViewCreative(creative.id)}
                                        >
                                            <div className="aspect-[1/1] bg-ch-black/40 relative overflow-hidden m-4 rounded-[2rem] border border-white/5">
                                                {creative.image_url ? (
                                                    <img
                                                        src={creative.image_url}
                                                        alt={creative.name}
                                                        className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-1000 ease-out"
                                                    />
                                                ) : (
                                                    <div className="w-full h-full flex items-center justify-center text-ch-text-dimmed opacity-20">
                                                        <config.icon className="w-12 h-12" />
                                                    </div>
                                                )}

                                                {creative.type === 'video' && (
                                                    <div className="absolute inset-0 flex items-center justify-center bg-black/10 group-hover:bg-black/30 transition-colors">
                                                        <div className="w-14 h-14 rounded-full bg-white/10 backdrop-blur-xl flex items-center justify-center border border-white/20 group-hover:scale-110 transition-transform">
                                                            <Play className="w-6 h-6 text-white fill-current translate-x-0.5" />
                                                        </div>
                                                    </div>
                                                )}

                                                <div className="absolute top-4 right-4 opacity-0 group-hover:opacity-100 transition-all scale-90 group-hover:scale-100">
                                                    <div className="bg-ch-white text-ch-black p-2.5 rounded-2xl shadow-2xl">
                                                        <Eye className="w-4 h-4" />
                                                    </div>
                                                </div>

                                                <div className="absolute top-4 left-4">
                                                    <span className={`text-[9px] font-bold uppercase tracking-widest px-2.5 py-1 rounded-full flex items-center gap-1.5 border ${typeColor.bg} ${typeColor.text} ${typeColor.border}`}>
                                                        <Icon className="w-3 h-3" />
                                                        {creative.type === 'video' ? 'ATIVO DE MOVIMENTO' :
                                                            creative.type === 'image' ? 'VISUAL ESTÁTICO' :
                                                                creative.type === 'carousel' ? 'MULTI-ATIVO' : 'OUTRO ATIVO'}
                                                    </span>
                                                </div>
                                            </div>

                                            <div className="px-6 pb-8 pt-2 flex-1 flex flex-col">
                                                <div className="mb-4">
                                                    <h3 className="font-bold text-ch-white group-hover:text-ch-orange transition-colors line-clamp-1 uppercase tracking-tight text-base">{creative.name}</h3>
                                                    <p className="text-[9px] font-bold text-ch-text-dimmed uppercase mt-2 tracking-widest flex items-center gap-2">
                                                        <Briefcase className="w-3 h-3 text-ch-orange" />
                                                        {creative.campaigns?.name || 'ATIVO_AVULSO'}
                                                    </p>
                                                </div>

                                                <div className="flex flex-wrap gap-2 mb-6">
                                                    <TagList tags={creative.tags} />
                                                    <div onClick={(e) => e.stopPropagation()}>
                                                        <TagSelector
                                                            entityId={creative.id}
                                                            entityType="creative"
                                                            selectedTags={creative.tags || []}
                                                        />
                                                    </div>
                                                </div>

                                                <div className="mt-auto pt-6 border-t border-white/5 grid grid-cols-2 gap-4">
                                                    <div className="flex flex-col">
                                                        <span className="text-[10px] font-bold text-ch-text-muted uppercase tracking-widest mb-1">Exposição</span>
                                                        <span className="text-sm font-bold text-ch-white tabular-nums">{formatNumber(creative.impressions || 0)}</span>
                                                    </div>
                                                    <div className="flex flex-col text-right">
                                                        <span className="text-[10px] font-bold text-ch-text-muted uppercase tracking-widest mb-1">Taxa de CTR</span>
                                                        <span className="text-sm font-bold text-ch-orange tabular-nums">
                                                            {creative.ctr ? `${Number(creative.ctr).toFixed(2)}%` : '0.00%'}
                                                        </span>
                                                    </div>
                                                </div>
                                            </div>
                                        </motion.div>
                                    );
                                })}
                            </div>
                        ) : (
                            <div className="glass rounded-[2.5rem] overflow-hidden border border-white/5 shadow-2xl">
                                <div className="divide-y divide-white/5">
                                    {creatives.map((creative) => {
                                        const config = getTypeConfig(creative.type);
                                        return (
                                            <div
                                                key={creative.id}
                                                className="p-6 flex items-center gap-8 hover:bg-white/[0.02] cursor-pointer group transition-all h-32"
                                                onClick={() => handleViewCreative(creative.id)}
                                            >
                                                <div className="w-20 h-20 rounded-2xl bg-ch-black/40 overflow-hidden flex-shrink-0 border border-white/5 relative group-hover:border-ch-orange/30 transition-colors shadow-2xl">
                                                    {creative.image_url ? (
                                                        <img
                                                            src={creative.image_url}
                                                            alt={creative.name}
                                                            className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700"
                                                        />
                                                    ) : (
                                                        <div className="w-full h-full flex items-center justify-center text-ch-text-dimmed opacity-20">
                                                            <config.icon className="w-8 h-8" />
                                                        </div>
                                                    )}
                                                    {creative.type === 'video' && (
                                                        <div className="absolute inset-0 flex items-center justify-center bg-black/20">
                                                            <Play className="w-5 h-5 text-white fill-current" />
                                                        </div>
                                                    )}
                                                </div>

                                                <div className="flex-1 min-w-0">
                                                    <h3 className="font-bold text-ch-white group-hover:text-ch-orange transition-colors truncate uppercase tracking-tight text-lg">{creative.name}</h3>
                                                    <div className="flex items-center gap-4 mt-2">
                                                        <p className="text-[9px] font-bold text-ch-text-dimmed uppercase tracking-widest flex items-center gap-1.5">
                                                            <Briefcase className="w-3 h-3 text-ch-orange" />
                                                            {creative.campaigns?.name || 'ASSET_ORPHAN'}
                                                        </p>
                                                        <div className="h-3 w-px bg-white/5" />
                                                        <TagList tags={creative.tags} />
                                                        <div onClick={(e) => e.stopPropagation()}>
                                                            <TagSelector
                                                                entityId={creative.id}
                                                                entityType="creative"
                                                                selectedTags={creative.tags || []}
                                                            />
                                                        </div>
                                                    </div>
                                                </div>

                                                <div className="flex items-center gap-14 pr-4">
                                                    <span className={`text-[9px] font-black uppercase tracking-[0.2em] px-3 py-1.5 rounded-full border bg-ch-black/40 text-white border-white/5 backdrop-blur-md w-32 text-center`}>
                                                        {creative.type === 'video' ? 'MOVIMENTO' :
                                                            creative.type === 'image' ? 'ESTÁTICO' :
                                                                creative.type === 'carousel' ? 'MULTI' : 'OUTRO'}
                                                    </span>

                                                    <div className="w-40 text-right">
                                                        <p className="text-[9px] font-black text-ch-text-dimmed uppercase tracking-[0.2em] mb-1.5">Exposição / Cliques</p>
                                                        <p className="text-base font-black text-ch-white tabular-nums italic">
                                                            {formatNumber(creative.impressions || 0)} <span className="text-ch-text-dimmed mx-1 opacity-20">/</span> {formatNumber(creative.clicks || 0)}
                                                        </p>
                                                    </div>
                                                    <div className="w-24 text-right">
                                                        <p className="text-[9px] font-black text-ch-text-dimmed uppercase tracking-[0.2em] mb-1.5">CTR Médio</p>
                                                        <p className="text-base font-black text-ch-white tabular-nums italic">
                                                            {creative.ctr ? `${Number(creative.ctr).toFixed(2)}%` : '-'}
                                                        </p>
                                                    </div>
                                                    <Button variant="ghost" size="icon" className="h-12 w-12 hover:bg-white/5 rounded-2xl border border-transparent hover:border-white/5">
                                                        <ChevronRight className="w-6 h-6 text-ch-text-dimmed group-hover:text-ch-orange transition-colors" />
                                                    </Button>
                                                </div>
                                            </div>
                                        );
                                    })}
                                </div>
                            </div>
                        )}

                        {/* Pagination Flux */}
                        {totalPages > 1 && (
                            <motion.div variants={item} className="px-4 py-8 flex items-center justify-between">
                                <p className="text-[10px] font-black text-ch-text-muted uppercase tracking-widest">
                                    PARCELA ATIVA: {page * PAGE_SIZE + 1}—{Math.min((page + 1) * PAGE_SIZE, total)} / {total} TOTAL
                                </p>
                                <div className="flex items-center gap-4">
                                    <Button
                                        variant="outline"
                                        size="sm"
                                        onClick={() => setPage(p => Math.max(0, p - 1))}
                                        disabled={page === 0}
                                        className="h-10 bg-ch-dark-gray/40 border-white/5 rounded-xl px-4 text-[10px] font-black uppercase tracking-widest hover:text-ch-orange transition-all"
                                    >
                                        <ChevronLeft className="w-4 h-4 mr-2" /> Anterior
                                    </Button>
                                    <p className="text-[10px] font-black text-ch-white uppercase tracking-widest">
                                        Bloco {page + 1} | {totalPages}
                                    </p>
                                    <Button
                                        variant="outline"
                                        size="sm"
                                        onClick={() => setPage(p => Math.min(totalPages - 1, p + 1))}
                                        disabled={page >= totalPages - 1}
                                        className="h-10 bg-ch-dark-gray/40 border-white/5 rounded-xl px-4 text-[10px] font-black uppercase tracking-widest hover:text-ch-orange transition-all"
                                    >
                                        Próximo <ChevronRight className="w-4 h-4 ml-2" />
                                    </Button>
                                </div>
                            </motion.div>
                        )}
                    </motion.div>
                ) : (
                    <motion.div
                        initial={{ opacity: 0, scale: 0.95 }}
                        animate={{ opacity: 1, scale: 1 }}
                        className="py-40 text-center flex flex-col items-center glass-premium border-none"
                    >
                        <div className="w-24 h-24 bg-ch-orange/5 border border-ch-orange/10 rounded-[2.5rem] flex items-center justify-center mb-8">
                            <ImageIcon className="w-10 h-10 text-ch-orange animate-pulse" />
                        </div>
                        <h2 className="text-2xl font-black text-ch-white uppercase italic tracking-tight mb-2">Acervo Digital Inexistente</h2>
                        <p className="text-ch-text-muted max-w-sm mx-auto font-medium mb-10 leading-relaxed uppercase text-[10px] tracking-widest text-center">
                            Nenhum ativo visual sincronizado para este workspace. <br />
                            Ative a integração com o Meta Business para importar.
                        </p>
                        <Button
                            variant="outline"
                            className="bg-ch-dark-gray/40 border-white/5 hover:bg-white/5 text-ch-orange font-black uppercase text-[11px] tracking-widest h-14 px-10 rounded-2xl transition-all"
                            onClick={() => { setSearch(''); setTypeFilter('all'); }}
                        >
                            Resetar Parâmetros de Busca
                        </Button>
                    </motion.div>
                )}
            </AnimatePresence>

            <AiDiagnosisModal
                isOpen={isAiModalOpen}
                onClose={() => setIsAiModalOpen(false)}
                data={aiData}
                isLoading={isAiLoading}
                onReanalyze={() => selectedCreativeId && handleRunDiagnosis(selectedCreativeId)}
                title="Diagnóstico Criativo"
            />
        </motion.div>
    );
}

import { AiDiagnosisModal } from '@/components/ai/AiDiagnosisModal';

const RefreshCw = ({ className }: { className?: string }) => (
    <svg className={className} xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
        <path d="M21 12a9 9 0 0 0-9-9 9.75 9.75 0 0 0-6.74 2.74L3 8" />
        <path d="M3 3v5h5" />
        <path d="M3 12a9 9 0 0 0 9 9 9.75 9.75 0 0 0 6.74-2.74L21 16" />
        <path d="M16 16h5v5" />
    </svg>
);

import { useState } from 'react';
import { useAuth } from '@/contexts/AuthContext';
import { useCompanyMetrics, MetricsPeriod } from '@/hooks/useCompanyMetrics';
import { useActiveCampaignsCount } from '@/hooks/useCampaigns';
import { useCreativesCount } from '@/hooks/useCreatives';
import { useAuditsCount, useRecentAudits, useIssuesWithHighPriority } from '@/hooks/useAudits';
import { useAccountHealth } from '@/hooks/useAccountHealth';
import {
    TrendingUp,
    TrendingDown,
    Users,
    Megaphone,
    FileCheck,
    ArrowUpRight,
    ArrowDownRight,
    BarChart3,
    DollarSign,
    MousePointer,
    Eye,
    Target,
    AlertTriangle,
    Check,
    Loader2,
    RefreshCw,
    Sparkles,
    Activity,
    ShieldAlert,
    Zap,
    Award,
    Briefcase,
    ShieldCheck,
    ChevronRight,
    ArrowRight
} from 'lucide-react';
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from '@/components/ui/select';
import { Button } from '@/components/ui/button';
import { format, formatDistanceToNow } from 'date-fns';
import { ptBR } from 'date-fns/locale';
import PerformanceChart from '@/components/PerformanceChart';
import { motion, AnimatePresence } from 'framer-motion';

const formatCurrency = (value: number) => {
    return new Intl.NumberFormat('pt-BR', {
        style: 'currency',
        currency: 'BRL',
    }).format(value);
};

const formatNumber = (value: number) => {
    if (value >= 1000000) return `${(value / 1000000).toFixed(1)}M`;
    if (value >= 1000) return `${(value / 1000).toFixed(1)}K`;
    return value.toLocaleString('pt-BR');
};

const formatPercent = (value: number) => {
    return `${value.toFixed(2)}%`;
};

const getVariation = (current: number, previous: number): { value: number; trend: 'up' | 'down' | 'neutral' } => {
    if (previous === 0) return { value: 0, trend: 'neutral' };
    const variation = ((current - previous) / previous) * 100;
    return {
        value: Math.abs(variation),
        trend: variation > 0 ? 'up' : variation < 0 ? 'down' : 'neutral',
    };
};

const container = {
    hidden: { opacity: 0 },
    show: {
        opacity: 1,
        transition: {
            staggerChildren: 0.05
        }
    }
};

const item = {
    hidden: { opacity: 0, y: 15 },
    show: { opacity: 1, y: 0 }
};

export default function Dashboard() {
    const { user } = useAuth();
    const [period, setPeriod] = useState<MetricsPeriod>('7d');

    const { data: metrics, isLoading: metricsLoading, refetch: refetchMetrics } = useCompanyMetrics(period);
    const { data: activeCampaigns } = useActiveCampaignsCount();
    const { data: creativesCount } = useCreativesCount();
    const { data: auditsCount } = useAuditsCount();
    const { data: recentAudits } = useRecentAudits(3);
    const { data: highPriorityIssues } = useIssuesWithHighPriority(3);
    const { data: accountHealth } = useAccountHealth();

    const hasData = metrics && (metrics.totalImpressions > 0 || metrics.totalSpend > 0);

    const metricCards = metrics ? [
        {
            title: 'ROAS (RETORNO)',
            value: `${metrics.globalRoas.toFixed(2)}x`,
            variation: getVariation(metrics.globalRoas, metrics.previousPeriod.globalRoas),
            icon: Target,
            color: 'emerald-400',
        },
        {
            title: 'CPA (CUSTO/RES.)',
            value: formatCurrency(metrics.globalCpa),
            variation: getVariation(metrics.globalCpa, metrics.previousPeriod.globalCpa),
            invertTrend: true,
            icon: DollarSign,
            color: 'blue-400',
        },
        {
            title: 'CONVERSÕES',
            value: formatNumber(metrics.totalConversions),
            variation: getVariation(metrics.totalConversions, metrics.previousPeriod.totalConversions),
            icon: Check,
            color: 'indigo-400',
        },
        {
            title: 'GASTO TOTAL',
            value: formatCurrency(metrics.totalSpend),
            variation: getVariation(metrics.totalSpend, metrics.previousPeriod.totalSpend),
            icon: DollarSign,
            color: 'amber-400',
        },
        {
            title: 'CTR (QUALIDADE)',
            value: formatPercent(metrics.avgCtr),
            variation: getVariation(metrics.avgCtr, metrics.previousPeriod.avgCtr),
            icon: MousePointer,
            color: 'teal-400',
        },
        {
            title: 'FREQUÊNCIA',
            value: metrics.avgFrequency.toFixed(2),
            variation: getVariation(metrics.avgFrequency, metrics.previousPeriod.avgFrequency),
            invertTrend: true, // Generally high frequency is bad (fatigue)
            icon: Activity,
            color: 'ch-orange',
        },
    ] : [];

    return (
        <motion.div
            initial="hidden"
            animate="show"
            variants={container}
            className="p-6 space-y-10"
        >
            {/* Command Central Header */}
            <motion.div
                variants={item}
                className="flex flex-col md:flex-row md:items-center justify-between gap-8"
            >
                <div>
                    <div className="flex items-center gap-3 mb-1">
                        <Sparkles className="w-4 h-4 text-ch-orange" />
                        <span className="text-[10px] font-bold text-ch-orange uppercase tracking-wide">Centro de Comando Neural</span>
                    </div>
                    <h1 className="text-4xl font-bold text-ch-white tracking-tight uppercase">
                        Bem-vindo, {user?.first_name || 'Operador'}
                    </h1>
                    <p className="text-ch-text-dimmed font-medium mt-1">
                        Sincronização em tempo real com seu ecossistema <span className="text-ch-white font-bold">Click.Hero</span>
                    </p>
                </div>

                <div className="flex items-center gap-4 bg-white/[0.02] p-2 rounded-2xl border border-white/5 backdrop-blur-sm shadow-xl">
                    <Select value={period} onValueChange={(v) => setPeriod(v as MetricsPeriod)}>
                        <SelectTrigger className="w-48 h-12 bg-transparent border-none font-black text-[10px] uppercase tracking-wide focus:ring-0">
                            <SelectValue />
                        </SelectTrigger>
                        <SelectContent className="bg-ch-black-soft border-white/10 font-black uppercase text-[10px]">
                            <SelectItem value="7d">Operação 7 Dias</SelectItem>
                            <SelectItem value="14d">Operação 14 Dias</SelectItem>
                            <SelectItem value="30d">Ciclo Mensal</SelectItem>
                            <SelectItem value="90d">Trimestre Estratégico</SelectItem>
                        </SelectContent>
                    </Select>
                    <div className="h-8 w-px bg-white/5" />
                    <Button
                        variant="ghost"
                        size="icon"
                        onClick={() => refetchMetrics()}
                        className="h-12 w-12 hover:bg-ch-orange/10 hover:text-ch-orange transition-all duration-300 rounded-xl"
                    >
                        <RefreshCw className="w-5 h-5" />
                    </Button>
                </div>
            </motion.div>

            {/* Neural Insights / Alerts */}
            <AnimatePresence>
                {accountHealth?.alerts && accountHealth.alerts.length > 0 && (
                    <motion.div
                        variants={item}
                        className="grid grid-cols-1 md:grid-cols-2 gap-4"
                    >
                        {accountHealth.alerts.map((alert, i) => (
                            <div
                                key={i}
                                className={`p-5 rounded-[1.5rem] flex items-center gap-5 border backdrop-blur-xl shadow-2xl overflow-hidden relative group ${alert.type === 'error' ? 'bg-rose-500/5 border-rose-500/20 text-rose-400' :
                                    alert.type === 'warning' ? 'bg-amber-500/5 border-amber-500/20 text-amber-400' :
                                        'bg-ch-orange/5 border-ch-orange/20 text-ch-orange'
                                    }`}
                            >
                                <div className={`p-3 rounded-2xl ${alert.type === 'error' ? 'bg-rose-500/10' :
                                    alert.type === 'warning' ? 'bg-amber-500/10' :
                                        'bg-ch-orange/10'
                                    } group-hover:scale-110 transition-transform`}>
                                    <ShieldAlert className="w-5 h-5" />
                                </div>
                                <div>
                                    <p className="text-[10px] font-bold uppercase tracking-wide opacity-40 mb-1">ALERTA DO SISTEMA</p>
                                    <p className="text-sm font-bold tracking-tight uppercase">{alert.message}</p>
                                </div>
                                <div className="absolute right-[-10px] bottom-[-10px] opacity-[0.03] rotate-12">
                                    <ShieldAlert className="w-24 h-24" />
                                </div>
                            </div>
                        ))}
                    </motion.div>
                )}
            </AnimatePresence>

            {/* Primary Metrics Layer */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                {[
                    {
                        title: 'ESTRUTURA ATIVA',
                        value: activeCampaigns?.toString() || '0',
                        sub: 'CAMPANHAS EM OTIMIZAÇÃO',
                        icon: Megaphone,
                        color: 'ch-orange'
                    },
                    {
                        title: 'ATIVOS CRIATIVOS',
                        value: creativesCount?.toString() || '0',
                        sub: 'BANCO DE DADOS ATUALIZADO',
                        icon: BarChart3,
                        color: 'blue-400'
                    },
                    {
                        title: 'QUALIDADE DO SISTEMA',
                        value: auditsCount?.total?.toString() || '0',
                        sub: `${highPriorityIssues?.length || 0} ALERTAS CRÍTICOS`,
                        icon: ShieldCheck,
                        color: 'indigo-400'
                    },
                    {
                        title: 'WORKSPACE',
                        value: user?.company?.name?.toUpperCase() || 'MINHA EMPRESA',
                        sub: user?.company?.plan ? `PLANO ${user.company.plan.toUpperCase()}` : 'PLANO STARTER',
                        icon: Briefcase,
                        color: 'emerald-400'
                    },
                ].map((stat) => (
                    <motion.div
                        key={stat.title}
                        variants={item}
                        whileHover={{ y: -5 }}
                        className="glass-card rounded-[2.5rem] p-8 border-white/5 relative overflow-hidden group shadow-2xl bg-white/[0.01]"
                    >
                        <div className="absolute top-0 right-0 p-8 opacity-[0.02] group-hover:opacity-[0.08] transition-opacity pointer-events-none transform translate-x-4">
                            <stat.icon className="w-24 h-24" />
                        </div>
                        <div className="flex items-center gap-4 mb-6">
                            <div className={`p-2.5 bg-${stat.color}/10 rounded-xl`}>
                                <stat.icon className={`w-5 h-5 text-${stat.color}`} />
                            </div>
                            <span className="text-[10px] font-bold text-ch-text-dimmed uppercase tracking-[.2em] leading-none">{stat.title}</span>
                        </div>
                        <p className={`font-bold text-ch-white tracking-tighter tabular-nums group-hover:text-ch-orange transition-colors duration-500 ${stat.title === 'WORKSPACE' ? 'text-xl line-clamp-1' : 'text-4xl'}`}>
                            {stat.value}
                        </p>
                        <div className="mt-6 flex items-center gap-2">
                            <div className={`w-1.5 h-1.5 rounded-full bg-${stat.color} animate-pulse`} />
                            <p className="text-[9px] font-bold text-ch-text-muted uppercase tracking-widest">{stat.sub}</p>
                        </div>
                    </motion.div>
                ))}
            </div>

            {/* Performance Engine Grid */}
            <div className="space-y-6">
                <motion.div variants={item} className="flex items-center gap-3 ml-1">
                    <Activity className="w-4 h-4 text-ch-orange" />
                    <h2 className="text-[11px] font-black text-ch-white uppercase tracking-widest">Matriz de Performance em Tempo Real</h2>
                </motion.div>

                {metricsLoading ? (
                    <div className="glass rounded-[2rem] p-32 flex flex-col items-center justify-center gap-6 border-white/5 shadow-inner bg-white/[0.01]">
                        <div className="relative">
                            <RefreshCw className="w-16 h-16 animate-spin text-ch-orange opacity-20" />
                            <Zap className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-6 h-6 text-ch-orange" />
                        </div>
                        <div className="text-center">
                            <p className="text-[10px] font-bold uppercase tracking-wide text-ch-orange mb-2">Sincronizando Camadas de Dados</p>
                            <p className="text-ch-text-dimmed font-medium uppercase text-[9px] tracking-widest">Acessando API Graph v18.0 do Meta...</p>
                        </div>
                    </div>
                ) : hasData ? (
                    <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-6 gap-6">
                        {metricCards.map((metric, idx) => {
                            const isPositive = metric.invertTrend
                                ? metric.variation.trend === 'down'
                                : metric.variation.trend === 'up';

                            return (
                                <motion.div
                                    key={metric.title}
                                    variants={item}
                                    whileHover={{ y: -5 }}
                                    className="glass rounded-3xl p-6 border-white/5 hover:border-white/10 transition-all shadow-xl flex flex-col h-40 bg-white/[0.02]"
                                >
                                    <div className="flex-1">
                                        <div className="flex items-center gap-2.5 mb-3">
                                            <div className={`w-1.5 h-1.5 rounded-full bg-${metric.color}`} />
                                            <span className="text-[9px] font-bold text-ch-text-dimmed uppercase tracking-normal leading-tight whitespace-nowrap">{metric.title}</span>
                                        </div>
                                        <p className="text-2xl font-bold text-ch-white tracking-tight tabular-nums">{metric.value}</p>
                                    </div>

                                    {metric.variation.value > 0 && (
                                        <div className={`inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full text-[9px] font-black tracking-widest w-fit shadow-lg ${isPositive ? 'bg-emerald-500/10 text-emerald-400 border border-emerald-500/20' : 'bg-rose-500/10 text-rose-400 border border-rose-500/20'
                                            }`}>
                                            {isPositive ? <ArrowUpRight className="w-3.5 h-3.5" /> : <ArrowDownRight className="w-3.5 h-3.5" />}
                                            {metric.variation.value.toFixed(1)}%
                                        </div>
                                    )}
                                </motion.div>
                            );
                        })}
                    </div>
                ) : (
                    <motion.div variants={item} className="glass rounded-[2rem] p-24 text-center border-white/5 shadow-2xl bg-white/[0.01]">
                        <div className="w-24 h-24 bg-ch-orange/5 border border-ch-orange/10 rounded-[2.5rem] flex items-center justify-center mx-auto mb-8">
                            <BarChart3 className="w-10 h-10 text-ch-orange animate-pulse" />
                        </div>
                        <h3 className="text-2xl font-bold text-ch-white mb-3 uppercase tracking-tight">Perda de Sinal Detectada</h3>
                        <p className="text-ch-text-dimmed font-medium max-w-sm mx-auto uppercase text-[9px] tracking-widest leading-relaxed">
                            Nenhum fluxo analítico detectado para o workspace selecionado no ciclo {period}.
                        </p>
                        <Button
                            variant="outline"
                            className="mt-10 bg-ch-dark-gray/40 border-white/5 hover:bg-white/5 text-ch-orange font-black uppercase text-[11px] tracking-widest h-14 px-10 rounded-2xl transition-all"
                            onClick={() => window.location.href = '/integracoes'}
                        >
                            Reconectar Base de Sinais
                        </Button>
                    </motion.div>
                )}
            </div>

            {/* Neural Chart Layer */}
            {hasData && metrics?.dailyData && (
                <motion.div variants={item} className="glass rounded-[3rem] p-10 border-white/5 shadow-2xl overflow-hidden relative group bg-white/[0.01]">
                    <div className="absolute top-0 right-0 p-12 opacity-[0.02] pointer-events-none transform translate-x-1/4 -translate-y-1/4 blur-2xl group-hover:opacity-[0.05] transition-opacity duration-1000">
                        <TrendingUp className="w-[600px] h-[600px]" />
                    </div>
                    <div className="flex flex-col md:flex-row items-center justify-between mb-12 relative z-10 gap-8">
                        <div>
                            <div className="flex items-center gap-3 mb-2">
                                <Zap className="w-5 h-5 text-ch-orange" />
                                <span className="text-[10px] font-bold text-ch-orange uppercase tracking-wider">Curva de Performance</span>
                            </div>
                            <h2 className="text-3xl font-bold text-ch-white tracking-tight uppercase">Analítica de Fluxo Neural</h2>
                            <p className="text-[10px] text-ch-text-dimmed font-bold uppercase tracking-widest mt-2">Mapeamento temporal de engajamento e conversão de rede</p>
                        </div>
                        <div className="flex items-center gap-10">
                            <div className="flex flex-col items-end">
                                <span className="text-[9px] font-black text-ch-text-dimmed uppercase tracking-wide mb-1.5 opacity-40">Gasto Acumulado</span>
                                <span className="text-3xl font-black text-emerald-400 tabular-nums leading-none">{formatCurrency(metrics.totalSpend)}</span>
                            </div>
                        </div>
                    </div>
                    <div className="h-[450px] relative z-10">
                        <PerformanceChart />
                    </div>
                </motion.div>
            )}

            {/* Tactical Feed Selection */}
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 pb-12">
                <motion.div variants={item} className="glass rounded-[2.5rem] p-10 border-white/5 shadow-2xl bg-white/[0.01] flex flex-col overflow-hidden relative">
                    <div className="absolute top-0 right-0 p-8 opacity-[0.01] pointer-events-none">
                        <Award className="w-64 h-64" />
                    </div>
                    <div className="flex items-center justify-between mb-10 relative z-10">
                        <div className="flex items-center gap-4">
                            <div className="p-3 bg-ch-orange/10 rounded-2xl">
                                <TrendingUp className="w-5 h-5 text-ch-orange" />
                            </div>
                            <div>
                                <h2 className="font-black text-ch-white uppercase tracking-tight text-lg">Auditoria de Performance IA</h2>
                                <p className="text-[9px] font-black text-ch-text-muted uppercase tracking-widest mt-1">Últimas validações de conformidade</p>
                            </div>
                        </div>
                        <Button variant="ghost" size="icon" className="h-12 w-12 hover:bg-white/10 rounded-2xl transition-all" onClick={() => window.location.href = '/auditorias'}>
                            <ArrowRight className="w-6 h-6 text-ch-text-muted hover:text-ch-orange" />
                        </Button>
                    </div>

                    <div className="space-y-4 relative z-10 flex-1">
                        {recentAudits && recentAudits.length > 0 ? (
                            recentAudits.map((audit) => (
                                <div key={audit.id} className="flex items-center justify-between p-5 rounded-[1.8rem] hover:bg-white/[0.03] border border-white/5 transition-all group cursor-pointer">
                                    <div className="flex items-center gap-5">
                                        <div className="w-16 h-16 bg-ch-black border border-white/10 rounded-2xl overflow-hidden shadow-2xl group-hover:scale-105 transition-transform duration-700">
                                            {audit.creative?.image_url ? (
                                                <img src={audit.creative.image_url} alt="" className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-1000" />
                                            ) : (
                                                <div className="w-full h-full flex items-center justify-center">
                                                    <Target className="w-6 h-6 text-ch-text-dimmed opacity-20" />
                                                </div>
                                            )}
                                        </div>
                                        <div>
                                            <p className="text-base font-black text-ch-white group-hover:text-ch-orange transition-colors line-clamp-1 uppercase tracking-tight">{audit.creative?.name || 'ASSET_PROBE_' + audit.id.slice(0, 4)}</p>
                                            <p className="text-[10px] text-ch-text-muted font-black mt-2 uppercase tracking-widest flex items-center gap-2">
                                                <RefreshCw className="w-3 h-3 text-ch-orange" />
                                                VERIFICADO {formatDistanceToNow(new Date(audit.created_at), { addSuffix: true, locale: ptBR })}
                                            </p>
                                        </div>
                                    </div>
                                    <div className={`flex flex-col items-center justify-center w-20 h-20 rounded-[1.3rem] border-2 transition-all group-hover:rotate-6 ${audit.compliance_score >= 80 ? 'bg-emerald-500/5 border-emerald-500/20 text-emerald-400' :
                                        audit.compliance_score >= 50 ? 'bg-amber-500/5 border-amber-500/20 text-amber-400' :
                                            'bg-rose-500/5 border-rose-500/20 text-rose-400'
                                        }`}>
                                        <span className="text-[9px] font-black uppercase tracking-[0.2em] opacity-40 mb-1">Score</span>
                                        <span className="text-xl font-black tabular-nums">{audit.compliance_score}%</span>
                                    </div>
                                </div>
                            ))
                        ) : (
                            <div className="py-24 text-center flex flex-col items-center flex-1 justify-center">
                                <Activity className="w-12 h-12 text-ch-text-dimmed mb-6 opacity-10 animate-pulse" />
                                <p className="text-[10px] text-ch-text-muted font-black uppercase tracking-[0.3em]">Aguardando Fluxo de Auditoria</p>
                            </div>
                        )}
                    </div>
                </motion.div>

                <motion.div variants={item} className="glass rounded-[2.5rem] p-10 border-white/5 shadow-2xl bg-white/[0.01] flex flex-col overflow-hidden relative">
                    <div className="absolute top-0 right-0 p-8 opacity-[0.01] pointer-events-none">
                        <AlertTriangle className="w-64 h-64" />
                    </div>
                    <div className="flex items-center justify-between mb-10 relative z-10">
                        <div className="flex items-center gap-4">
                            <div className="p-3 bg-rose-500/10 rounded-2xl">
                                <FileCheck className="w-5 h-5 text-rose-500" />
                            </div>
                            <div>
                                <h2 className="font-black text-ch-white uppercase tracking-tight text-lg">Riscos do Ecossistema</h2>
                                <p className="text-[9px] font-black text-ch-text-muted uppercase tracking-widest mt-1">Violações Críticas de Performance/Identidade</p>
                            </div>
                        </div>
                    </div>

                    <div className="space-y-4 relative z-10 flex-1">
                        {highPriorityIssues && highPriorityIssues.length > 0 ? (
                            highPriorityIssues.map((issue) => (
                                <div key={issue.id} className="flex items-center justify-between p-6 rounded-[1.8rem] bg-rose-500/[0.03] border border-rose-500/10 hover:border-rose-500/40 transition-all group cursor-pointer shadow-xl">
                                    <div className="flex items-center gap-6">
                                        <div className="w-16 h-16 bg-rose-500/10 border border-rose-500/20 rounded-2xl flex items-center justify-center shadow-2xl group-hover:scale-105 group-hover:rotate-3 transition-transform duration-500">
                                            <AlertTriangle className="w-8 h-8 text-rose-500 group-hover:animate-bounce" />
                                        </div>
                                        <div>
                                            <p className="text-base font-black text-ch-white line-clamp-1 uppercase tracking-tight">{issue.creative?.name || 'CONFORMITY_BREACH'}</p>
                                            <div className="flex items-center gap-2.5 mt-2">
                                                <span className="w-2 h-2 rounded-full bg-rose-500 animate-ping" />
                                                <p className="text-[10px] text-rose-500/90 font-black uppercase tracking-[0.2em]">AÇÃO IMEDIATA NECESSÁRIA</p>
                                            </div>
                                        </div>
                                    </div>
                                    <div className="flex flex-col items-center justify-center w-20 h-20 rounded-[1.3rem] border-2 bg-rose-500/20 border-rose-500/30 text-rose-500 shadow-2xl skew-x-[-2deg]">
                                        <span className="text-[9px] font-black uppercase tracking-[0.2em] opacity-60 mb-1">Estado</span>
                                        <span className="text-xs font-black tracking-widest">CRÍTICO</span>
                                    </div>
                                </div>
                            ))
                        ) : (
                            <div className="py-24 text-center flex flex-col items-center flex-1 justify-center">
                                <div className="w-20 h-20 bg-emerald-500/5 rounded-[2rem] border border-emerald-500/10 flex items-center justify-center mb-8 shadow-2xl">
                                    <Check className="w-8 h-8 text-emerald-500" />
                                </div>
                                <h4 className="text-lg font-black text-ch-white uppercase tracking-tight">Full Compliance Matrix</h4>
                                <p className="text-[10px] text-ch-text-dimmed mt-3 font-black uppercase tracking-[.3em]">Zero anomalias detectadas no ecossistema.</p>
                            </div>
                        )}
                    </div>
                </motion.div>
            </div>
        </motion.div>
    );
}

import { useState } from 'react';
import { useCompany, useUpdateCompany, useCompanyStats } from '@/hooks/useCompany';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import {
    Building2,
    Users,
    Megaphone,
    Link2,
    FileCheck,
    Loader2,
    Save,
} from 'lucide-react';

export default function Empresa() {
    const { data: company, isLoading } = useCompany();
    const { data: stats } = useCompanyStats();
    const updateCompany = useUpdateCompany();

    const [form, setForm] = useState<{
        name: string;
    } | null>(null);

    const hasChanges = form !== null;

    const handleEdit = () => {
        if (company) {
            setForm({
                name: company.name || '',
            });
        }
    };

    const handleSave = async () => {
        if (!form) return;
        await updateCompany.mutateAsync(form);
        setForm(null);
    };

    const handleCancel = () => {
        setForm(null);
    };

    if (isLoading) {
        return (
            <div className="p-6 flex items-center justify-center min-h-[400px]">
                <Loader2 className="w-6 h-6 animate-spin text-ch-orange" />
            </div>
        );
    }

    return (
        <div className="p-6 space-y-6">
            {/* Header */}
            <div className="flex items-center justify-between">
                <div>
                    <h1 className="text-2xl font-bold text-ch-white">Empresa</h1>
                    <p className="text-ch-text-muted">
                        Configure as informações da sua empresa
                    </p>
                </div>
                {!hasChanges ? (
                    <Button onClick={handleEdit} variant="outline" className="border-ch-dark-gray">
                        Editar
                    </Button>
                ) : (
                    <div className="flex gap-2">
                        <Button onClick={handleCancel} variant="outline" className="border-ch-dark-gray">
                            Cancelar
                        </Button>
                        <Button
                            onClick={handleSave}
                            disabled={updateCompany.isPending}
                            className="bg-ch-orange hover:bg-ch-orange/90"
                        >
                            {updateCompany.isPending ? (
                                <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                            ) : (
                                <Save className="w-4 h-4 mr-2" />
                            )}
                            Salvar
                        </Button>
                    </div>
                )}
            </div>

            {/* Limits Card */}
            <div className="glass rounded-xl p-6">
                <div className="flex items-center gap-4 mb-6">
                    <div className="p-3 rounded-xl bg-ch-orange/10">
                        <Building2 className="w-6 h-6 text-ch-orange" />
                    </div>
                    <div>
                        <p className="text-sm text-ch-text-muted">Plano Atual</p>
                        <p className="text-xl font-bold text-ch-orange">Plano Básico</p>
                    </div>
                </div>

                {/* Limits */}
                <div className="grid grid-cols-3 gap-6 pt-6 border-t border-white/5">
