                        <div className="mt-2 h-1.5 bg-ch-dark-gray rounded-full overflow-hidden">
                            <div
                                className="h-full bg-ch-orange transition-all"
                                style={{ width: `${Math.min(100, ((stats?.totalCampaigns || 0) / (company?.max_campaigns || 10)) * 100)}%` }}
                            />
                        </div>
                    </div>
                    <div>
                        <p className="text-sm text-ch-text-dimmed">Integrações</p>
                        <p className="text-lg font-semibold text-ch-white">
                            {stats?.activeIntegrations || 0} / {company?.max_integrations || 2}
                        </p>
                        <div className="mt-2 h-1.5 bg-ch-dark-gray rounded-full overflow-hidden">
                            <div
                                className="h-full bg-blue-500 transition-all"
                                style={{ width: `${Math.min(100, ((stats?.activeIntegrations || 0) / (company?.max_integrations || 2)) * 100)}%` }}
                            />
                        </div>
                    </div>
                    <div>
                        <p className="text-sm text-ch-text-dimmed">Usuários</p>
                        <p className="text-lg font-semibold text-ch-white">
                            {stats?.totalUsers || 0} / {company?.max_users || 5}
                        </p>
                        <div className="mt-2 h-1.5 bg-ch-dark-gray rounded-full overflow-hidden">
                            <div
                                className="h-full bg-purple-500 transition-all"
                                style={{ width: `${Math.min(100, ((stats?.totalUsers || 0) / (company?.max_users || 5)) * 100)}%` }}
                            />
                        </div>
                    </div>
                </div>
            </div>

            {/* Company Info */}
            <div className="glass rounded-xl p-6 space-y-6">
                <h2 className="font-semibold text-ch-white">Informações da Empresa</h2>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <div className="space-y-2">
                        <label className="text-sm text-ch-text-muted">Nome da Empresa</label>
                        {hasChanges ? (
                            <Input
                                value={form?.name || ''}
                                onChange={(e) => setForm(f => f && { ...f, name: e.target.value })}
                                className="bg-ch-dark-gray border-ch-dark-gray"
                            />
