            {/* Stats */}
            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                <div className="glass rounded-xl p-5">
                    <div className="flex items-center gap-3">
                        <div className="p-2 bg-ch-orange/10 rounded-lg">
                            <Megaphone className="w-5 h-5 text-ch-orange" />
                        </div>
                        <div>
                            <p className="text-2xl font-bold text-ch-white">{stats?.totalCampaigns || 0}</p>
                            <p className="text-sm text-ch-text-muted">Campanhas</p>
                        </div>
                    </div>
                </div>
                <div className="glass rounded-xl p-5">
                    <div className="flex items-center gap-3">
                        <div className="p-2 bg-blue-500/10 rounded-lg">
                            <Link2 className="w-5 h-5 text-blue-500" />
                        </div>
                        <div>
                            <p className="text-2xl font-bold text-ch-white">{stats?.activeIntegrations || 0}</p>
                            <p className="text-sm text-ch-text-muted">Integrações</p>
                        </div>
                    </div>
                </div>
                <div className="glass rounded-xl p-5">
                    <div className="flex items-center gap-3">
                        <div className="p-2 bg-purple-500/10 rounded-lg">
                            <Users className="w-5 h-5 text-purple-500" />
                        </div>
                        <div>
                            <p className="text-2xl font-bold text-ch-white">{stats?.totalUsers || 0}</p>
                            <p className="text-sm text-ch-text-muted">Usuários</p>
                        </div>
                    </div>
                </div>
                <div className="glass rounded-xl p-5">
                    <div className="flex items-center gap-3">
                        <div className="p-2 bg-green-500/10 rounded-lg">
                            <FileCheck className="w-5 h-5 text-green-500" />
                        </div>
                        <div>
                            <p className="text-2xl font-bold text-ch-white">{stats?.totalAudits || 0}</p>
                            <p className="text-sm text-ch-text-muted">Auditorias</p>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}

