                        </div>
                    </div>

                    <div className="text-center space-y-6">
                        <div className="space-y-2">
                            <h2 className="text-5xl font-black text-transparent bg-clip-text bg-gradient-to-r from-white via-white to-gray-400 tracking-tighter uppercase">
                                Inteligência <br /> <span className="text-ch-orange">Publicitária</span>
                            </h2>
                            <p className="text-ch-text-muted text-sm font-medium tracking-[0.2em] uppercase max-w-md mx-auto leading-relaxed">
                                Domine seus dados. Escale seus resultados.
                            </p>
                        </div>

                        {/* Feature Pills */}
                        <div className="flex flex-wrapjustify-center gap-3 pt-4">
                            {[
                                { icon: Activity, label: "Monitoramento em Tempo Real" },
                                { icon: BarChart2, label: "Análise Preditiva" },
                                { icon: Globe, label: "Escala Global" }
                            ].map((feature, i) => (
                                <div key={i} className="flex items-center gap-2 px-4 py-2 rounded-full bg-white/5 border border-white/5 backdrop-blur-sm text-xs font-medium text-ch-text-muted hover:bg-white/10 hover:text-ch-white transition-colors cursor-default">
                                    <feature.icon className="w-3.5 h-3.5 text-ch-orange" />
                                    {feature.label}
                                </div>
                            ))}
