    console.error("404 Error: User attempted to access non-existent route:", location.pathname);
  }, [location.pathname]);

  return (
    <div className="flex min-h-screen items-center justify-center bg-muted">
      <div className="text-center">
        <h1 className="mb-4 text-4xl font-bold">404</h1>
        <p className="mb-4 text-xl text-muted-foreground">Oops! Page not found</p>
        <a href="/" className="text-primary underline hover:text-primary/90">
          Return to Home
        </a>
      </div>
    </div>
  );
};

export default NotFound;

import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useQuery, useMutation } from '@tanstack/react-query';
import { supabase, supabaseUrl } from '@/integrations/supabase/client';
import { Button } from '@/components/ui/button';
import { Card, CardContent } from '@/components/ui/card';
import { Progress } from "@/components/ui/progress";
import { toast } from 'sonner';
import {
    ArrowLeft,
    CheckCircle2,
    Target,
    Users,
    Megaphone,
    Rocket,
    Loader2
} from 'lucide-react';

// Components (will create next)
import StepCampanha from '@/components/campaign-wizard/StepCampanha';
import StepAdSet from '@/components/campaign-wizard/StepAdSet';
import StepAnuncio from '@/components/campaign-wizard/StepAnuncio';
import StepReview from '@/components/campaign-wizard/StepReview';

import { CampaignWizardState, defaultWizardState } from '@/types/campaign-wizard';

export default function NovaCampanha() {
    const navigate = useNavigate();
    const [currentStep, setCurrentStep] = useState(1);
    const [formData, setFormData] = useState<CampaignWizardState>(defaultWizardState);

    // Fetch integrations to ensure we have an account to create campaigns in
    const { data: integrations, isLoading: isLoadingInteg } = useQuery({
        queryKey: ['integrations'],
        queryFn: async () => {
            const { data, error } = await supabase
                .from('integrations')
                .select('*')
                .eq('platform', 'meta')
                .eq('status', 'active');
            if (error) throw error;
            return data;
        }
    });

    const createMutation = useMutation({
        mutationFn: async (data: CampaignWizardState) => {
            if (!data.integration_id) throw new Error('Selecione uma conta de anúncio.');

            const { data: sessionData } = await supabase.auth.getSession();
            const token = sessionData.session?.access_token;

            const response = await fetch(`${supabaseUrl}/functions/v1/meta-create-campaign`, {
                method: 'POST',
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify(data),
            });

            const result = await response.json();
            if (!response.ok) {
                throw new Error(result.error || 'Erro ao criar campanha');
            }
            return result;
        },
        onSuccess: () => {
            toast.success('Campanha criada com sucesso!');
            navigate('/campanhas');
        },
        onError: (error) => {
            toast.error(`Erro: ${error.message}`);
        }
    });

    const updateFormData = (section: 'campaign' | 'adset' | 'ad', data: any) => {
        setFormData(prev => ({
            ...prev,
            [section]: { ...prev[section], ...data }
        }));
    };

    const setIntegrationId = (id: string) => {
        setFormData(prev => ({ ...prev, integration_id: id }));
    }

    const nextStep = () => {
        if (currentStep < 4) setCurrentStep(c => c + 1);
    };

    const prevStep = () => {
        if (currentStep > 1) setCurrentStep(c => c - 1);
    };

    const steps = [
        { id: 1, title: 'Campanha', icon: Target },
        { id: 2, title: 'Conjunto', icon: Users },
        { id: 3, title: 'Anúncio', icon: Megaphone },
        { id: 4, title: 'Revisão', icon: Rocket },
    ];

    const progress = (currentStep / 4) * 100;

    if (isLoadingInteg) {
        return (
            <div className="flex h-screen items-center justify-center">
                <Loader2 className="w-8 h-8 animate-spin text-ch-orange" />
            </div>
        );
    }

    return (
        <div className="min-h-screen bg-ch-bg p-6">
            <div className="max-w-5xl mx-auto space-y-8">
                {/* Header */}
                <div className="flex items-center gap-4">
                    <Button variant="ghost" size="icon" onClick={() => navigate('/campanhas')}>
                        <ArrowLeft className="w-5 h-5" />
                    </Button>
                    <div>
                        <h1 className="text-2xl font-bold text-ch-white">Nova Campanha</h1>
                        <p className="text-ch-text-muted">Crie sua campanha passo a passo</p>
                    </div>
                </div>

                {/* Progress */}
                <div className="space-y-4">
                    <Progress value={progress} className="h-2" />
                    <div className="flex justify-between relative">
                        {steps.map((step) => {
                            const Icon = step.icon;
                            const isActive = currentStep >= step.id;
                            const isCurrent = currentStep === step.id;

                            return (
                                <div key={step.id} className="flex flex-col items-center gap-2 z-10">
                                    <div className={`
                                        w-10 h-10 rounded-full flex items-center justify-center transition-all duration-300
                                        ${isActive ? 'bg-ch-orange text-white' : 'bg-ch-dark-gray text-ch-text-muted'}
                                        ${isCurrent ? 'ring-4 ring-ch-orange/20' : ''}
                                    `}>
                                        <Icon className="w-5 h-5" />
                                    </div>
                                    <span className={`text-sm font-medium ${isActive ? 'text-ch-white' : 'text-ch-text-muted'}`}>
                                        {step.title}
                                    </span>
                                </div>
                            );
                        })}
                    </div>
                </div>

                {/* Content */}
                <Card className="glass border-white/5 min-h-[500px]">
                    <CardContent className="p-6">
                        {currentStep === 1 && (
                            <StepCampanha
                                data={formData.campaign}
                                updateData={(d) => updateFormData('campaign', d)}
                                integrationId={formData.integration_id}
                                setIntegrationId={setIntegrationId}
                                integrations={integrations || []}
                            />
                        )}
                        {currentStep === 2 && (
                            <StepAdSet
                                data={formData.adset}
                                updateData={(d) => updateFormData('adset', d)}
                            />
                        )}
                        {currentStep === 3 && (
                            <StepAnuncio
                                data={formData.ad}
                                fullData={formData}
                                updateData={(d) => updateFormData('ad', d)}
                            />
                        )}
                        {currentStep === 4 && (
                            <StepReview
                                data={formData}
                            />
                        )}
                    </CardContent>
                </Card>

                {/* Footer Navigation */}
                <div className="flex justify-between pt-4">
                    <Button
                        variant="ghost"
                        onClick={prevStep}
                        disabled={currentStep === 1 || createMutation.isPending}
                        className="text-ch-text-muted hover:text-white hover:bg-white/10"
                    >
                        Voltar
                    </Button>

                    {currentStep < 4 ? (
                        <Button
                            onClick={nextStep}
                            disabled={!formData.integration_id && currentStep === 1}
                            className="bg-ch-orange hover:bg-ch-orange/90 text-white min-w-[120px]"
                        >
                            Próximo
                        </Button>
                    ) : (
                        <Button
                            onClick={() => createMutation.mutate(formData)}
                            disabled={createMutation.isPending}
                            className="bg-green-600 hover:bg-green-700 text-white min-w-[120px]"
                        >
                            {createMutation.isPending ? (
                                <Loader2 className="w-4 h-4 animate-spin mr-2" />
                            ) : (
                                <Rocket className="w-4 h-4 mr-2" />
                            )}
                            Publicar Campanha
                        </Button>
                    )}
                </div>
            </div>
        </div>
    );
}

import { useState } from 'react';
import { usePolicies, Policy, CreatePolicyInput } from '@/hooks/usePolicies';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import {
    Dialog,
    DialogContent,
    DialogHeader,
    DialogTitle,
    DialogTrigger,
} from '@/components/ui/dialog';
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from '@/components/ui/select';
import {
    DropdownMenu,
    DropdownMenuContent,
    DropdownMenuItem,
    DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu';
import { Switch } from '@/components/ui/switch';
import { Label } from '@/components/ui/label';
import {
    Shield,
    Plus,
    Search,
    MoreHorizontal,
    Edit2,
    Trash2,
    Copy,
    Loader2,
    FileText,
    Tag,
    Ban,
    CheckCircle,
    AlertTriangle,
    Globe,
    Target,
    Zap,
    Sparkles,
    ChevronRight,
    Award,
    Activity,
    ShieldCheck,
    Briefcase,
    DollarSign,
    TrendingUp,
    Calendar,
    Archive
} from 'lucide-react';
import { format } from 'date-fns';
import { ptBR } from 'date-fns/locale';
import { motion, AnimatePresence } from 'framer-motion';

const POLICY_TEMPLATES: Partial<CreatePolicyInput>[] = [
    {
        name: 'Conformidade Básica',
        description: 'Política padrão para garantir integridade básica de anúncios',
        scope: 'global',
        prohibited_keywords: ['grátis', 'garantido', 'sem risco', 'milagre'],
        min_text_length: 10,
        max_text_length: 500,
        status: 'active',
    },
    {
        name: 'Performance Elite',
        description: 'Filtros rigorosos para ativos de alta conversão',
        scope: 'global',
        ctr_min: 1.5,
        ctr_target: 3.0,
        cpc_max: 5.0,
        cpc_target: 2.0,
        status: 'active',
    },
    {
        name: 'Identidade Premium',
        description: 'Diretrizes estritas de branding e estética visual',
        scope: 'global',
        requires_logo: true,
        requires_brand_colors: true,
        status: 'active',
    },
];

const container = {
    hidden: { opacity: 0 },
    show: {
        opacity: 1,
        transition: {
            staggerChildren: 0.05
        }
    }
};

const item = {
    hidden: { opacity: 0, y: 15 },
    show: { opacity: 1, y: 0 }
};

export default function Politicas() {
    const { policies, isLoading, createPolicy, updatePolicy, deletePolicy } = usePolicies();
    const [search, setSearch] = useState('');
    const [isDialogOpen, setIsDialogOpen] = useState(false);
    const [editingPolicy, setEditingPolicy] = useState<Policy | null>(null);
    const [form, setForm] = useState<Partial<CreatePolicyInput>>({
        name: '',
        description: '',
        scope: 'global',
        status: 'active',
        prohibited_keywords: [],
        required_keywords: [],
    });

    const filteredPolicies = policies.filter(p =>
        p.name.toLowerCase().includes(search.toLowerCase()) ||
        p.description?.toLowerCase().includes(search.toLowerCase())
    );

    const handleSubmit = async () => {
        if (!form.name) return;

        if (editingPolicy) {
            await updatePolicy.mutateAsync({ id: editingPolicy.id, ...form });
        } else {
            await createPolicy.mutateAsync(form as CreatePolicyInput);
        }
        handleCloseDialog();
    };

    const handleEdit = (policy: Policy) => {
        setEditingPolicy(policy);
        setForm({
            name: policy.name,
            description: policy.description || '',
            scope: policy.scope as any || 'global',
            status: policy.status as any || 'active',
            required_keywords: policy.required_keywords || [],
            prohibited_keywords: policy.prohibited_keywords || [],
            required_phrases: policy.required_phrases || [],
            prohibited_phrases: policy.prohibited_phrases || [],
            min_text_length: policy.min_text_length || undefined,
            max_text_length: policy.max_text_length || undefined,
            requires_logo: policy.requires_logo || false,
            requires_brand_colors: policy.requires_brand_colors || false,
            ctr_min: policy.ctr_min || undefined,
            ctr_target: policy.ctr_target || undefined,
            cpc_max: policy.cpc_max || undefined,
            cpc_target: policy.cpc_target || undefined,
        });
        setIsDialogOpen(true);
    };

    const handleCloseDialog = () => {
        setIsDialogOpen(false);
        setEditingPolicy(null);
        setForm({
            name: '',
            description: '',
            scope: 'global',
            status: 'active',
            prohibited_keywords: [],
            required_keywords: [],
        });
    };

    const handleDelete = async (id: string) => {
        if (confirm('Tem certeza que deseja excluir esta política?')) {
            await deletePolicy.mutateAsync(id);
        }
    };

    const handleUseTemplate = (template: Partial<CreatePolicyInput>) => {
        setForm({ ...form, ...template });
    };

    const getStatusBadge = (status: string | null) => {
        const config: Record<string, { label: string, color: string }> = {
            active: { label: 'Manual Ativo', color: 'emerald-500' },
            draft: { label: 'Rascunho Técnico', color: 'amber-500' },
            archived: { label: 'Legado', color: 'ch-text-dimmed' },
        };
        const cfg = config[status || 'draft'] || config.draft;
        return (
            <span className={`text-[9px] font-black uppercase tracking-widest px-2.5 py-1 rounded-full bg-${cfg.color}/10 text-${cfg.color} border border-${cfg.color}/20`}>
                {cfg.label}
            </span>
        );
    };

    const getScopeBadge = (scope: string | null) => {
        return scope === 'campaign' ? (
            <span className="text-[9px] font-black uppercase tracking-widest px-2.5 py-1 rounded-full bg-blue-500/10 text-blue-400 flex items-center gap-1.5 border border-blue-500/20">
                <Target className="w-3 h-3" />
                Campanha
            </span>
        ) : (
            <span className="text-[9px] font-black uppercase tracking-widest px-2.5 py-1 rounded-full bg-purple-500/10 text-purple-400 flex items-center gap-1.5 border border-purple-500/20">
                <Globe className="w-3 h-3" />
                Global
            </span>
        );
    };

    return (
        <motion.div
            initial="hidden"
            animate="show"
            variants={container}
            className="p-6 space-y-8"
        >
            {/* Header */}
            <motion.div variants={item} className="flex flex-col md:flex-row md:items-center justify-between gap-6">
                <div>
                    <div className="flex items-center gap-3 mb-1">
                        <ShieldCheck className="w-4 h-4 text-ch-orange" />
                        <span className="text-[10px] font-black text-ch-orange uppercase tracking-wide">Central de Segurança</span>
                    </div>
                    <h1 className="text-3xl font-black text-ch-white tracking-tight uppercase">Políticas de Compliance</h1>
                    <p className="text-ch-text-muted font-medium mt-1">Defina o código de conduta para automação de criativos.</p>
                </div>

                <Dialog open={isDialogOpen} onOpenChange={(open) => open ? setIsDialogOpen(true) : handleCloseDialog()}>
                    <DialogTrigger asChild>
                        <Button className="bg-ch-white hover:bg-ch-orange text-ch-black font-black uppercase tracking-widest rounded-xl transition-all h-12 px-8 shadow-xl group">
                            <Plus className="w-4 h-4 mr-2 group-hover:rotate-90 transition-transform" />
                            Criar Protocolo
                        </Button>
                    </DialogTrigger>
                    <DialogContent className="max-w-3xl max-h-[90vh] overflow-y-auto bg-ch-black-soft border-white/10 p-0 rounded-[2.5rem] shadow-[0_0_100px_rgba(242,106,33,0.1)]">
                        <div className="p-8 border-b border-white/5 bg-white/[0.01] flex items-center justify-between sticky top-0 backdrop-blur-3xl z-10">
                            <div className="flex items-center gap-4">
                                <div className="p-2.5 bg-ch-orange/10 rounded-xl">
                                    <ShieldCheck className="w-5 h-5 text-ch-orange" />
                                </div>
                                <div>
                                    <h2 className="text-xl font-black text-ch-white uppercase tracking-tight">
                                        {editingPolicy ? 'Refinar Protocolo' : 'Novo Protocolo IA'}
                                    </h2>
                                    <p className="text-[10px] font-black text-ch-text-muted uppercase tracking-wide mt-1">Configuração de Regras de Negócio</p>
                                </div>
                            </div>
                            <Button variant="ghost" className="text-ch-text-muted hover:text-ch-white" onClick={handleCloseDialog}>Fechar</Button>
                        </div>

                        <div className="p-10 space-y-10">
                            {/* Templates Quick Select */}
                            {!editingPolicy && (
                                <div className="space-y-4">
                                    <div className="flex items-center gap-2">
                                        <Sparkles className="w-3 h-3 text-ch-orange" />
                                        <Label className="text-[10px] font-black text-ch-text-muted uppercase tracking-widest">Acelerar com Presets IA</Label>
                                    </div>
                                    <div className="flex flex-wrap gap-3">
                                        {POLICY_TEMPLATES.map((template, i) => (
                                            <Button
                                                key={i}
                                                variant="outline"
                                                onClick={() => handleUseTemplate(template)}
                                                className="bg-ch-dark-gray/40 border-white/5 h-12 rounded-xl px-5 text-[10px] font-black uppercase tracking-widest hover:border-ch-orange/50 hover:text-ch-orange transition-all group"
                                            >
                                                <Copy className="w-3.5 h-3.5 mr-2 group-hover:scale-110 transition-transform" />
                                                {template.name}
                                            </Button>
                                        ))}
                                    </div>
                                </div>
                            )}

                            {/* Core Identity */}
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                                <div className="space-y-4">
                                    <Label className="text-[10px] font-black text-ch-text-muted uppercase tracking-widest ml-1">Identificação do Protocolo</Label>
                                    <Input
                                        value={form.name}
                                        onChange={(e) => setForm({ ...form, name: e.target.value })}
                                        placeholder="EX: POLÍTICA BRANDING 2024"
                                        className="bg-ch-dark-gray/40 border-white/5 h-16 rounded-2xl text-ch-white font-black uppercase tracking-widest px-6 focus:border-ch-orange/50 transition-all placeholder:opacity-20"
                                    />
                                </div>
                                <div className="space-y-4">
                                    <Label className="text-[10px] font-black text-ch-text-muted uppercase tracking-widest ml-1">Escopo de Aplicação</Label>
                                    <Select
                                        value={form.scope}
                                        onValueChange={(v) => setForm({ ...form, scope: v as any })}
                                    >
                                        <SelectTrigger className="bg-ch-dark-gray/40 border-white/5 h-16 rounded-2xl text-ch-white font-black uppercase tracking-widest px-6 focus:border-ch-orange/50 transition-all">
                                            <SelectValue />
                                        </SelectTrigger>
                                        <SelectContent className="bg-ch-black-soft border-white/10 uppercase font-black text-[10px] tracking-widest">
                                            <SelectItem value="global" className="tracking-widest">Infraestrutura Global</SelectItem>
                                            <SelectItem value="campaign" className="tracking-widest">Específico p/ Campanha</SelectItem>
                                        </SelectContent>
                                    </Select>
                                </div>
                                <div className="col-span-1 md:col-span-2 space-y-4">
                                    <Label className="text-[10px] font-black text-ch-text-muted uppercase tracking-widest ml-1">Descrição Executiva</Label>
                                    <Textarea
                                        value={form.description}
                                        onChange={(e) => setForm({ ...form, description: e.target.value })}
                                        placeholder="DESCREVA O OBJETIVO ANALÍTICO DESTA REGRA..."
                                        className="bg-ch-dark-gray/40 border-white/5 rounded-2xl text-ch-white font-medium p-6 focus:border-ch-orange/50 transition-all placeholder:opacity-20 min-h-[100px]"
                                    />
                                </div>
                            </div>

                            {/* Lexical Rules */}
                            <div className="space-y-6">
                                <div className="flex items-center gap-3">
                                    <Tag className="w-5 h-5 text-ch-orange" />
                                    <h3 className="text-sm font-black text-ch-white uppercase tracking-tight">Lexicografia & Proibições</h3>
                                </div>
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                                    <div className="space-y-4 group">
                                        <Label className="text-[9px] font-black text-emerald-500 uppercase tracking-widest flex items-center gap-2">
                                            <CheckCircle className="w-3 h-3" /> Termos Obrigatórios
                                        </Label>
                                        <Textarea
                                            value={(form.required_keywords || []).join(', ')}
                                            onChange={(e) => setForm({
                                                ...form,
                                                required_keywords: e.target.value.split(',').map(s => s.trim()).filter(Boolean),
                                            })}
                                            placeholder="MARCA, OFERTA, PRODUTO"
                                            className="bg-emerald-500/[0.02] border-white/5 rounded-2xl text-ch-white font-bold p-5 focus:border-emerald-500/30 transition-all uppercase text-xs"
                                        />
                                    </div>
                                    <div className="space-y-4 group">
                                        <Label className="text-[9px] font-black text-rose-500 uppercase tracking-widest flex items-center gap-2">
                                            <Ban className="w-3 h-3" /> Gatilhos Proibidos
                                        </Label>
                                        <Textarea
                                            value={(form.prohibited_keywords || []).join(', ')}
                                            onChange={(e) => setForm({
                                                ...form,
                                                prohibited_keywords: e.target.value.split(',').map(s => s.trim()).filter(Boolean),
                                            })}
                                            placeholder="GRÁTIS, MILAGRE, GARANTIDO"
                                            className="bg-rose-500/[0.02] border-white/5 rounded-2xl text-ch-white font-bold p-5 focus:border-rose-500/30 transition-all uppercase text-xs"
                                        />
                                    </div>
                                </div>
                            </div>

                            {/* Thresholds & KPIs */}
                            <div className="space-y-6">
                                <div className="flex items-center gap-3">
                                    <Activity className="w-5 h-5 text-ch-orange" />
                                    <h3 className="text-sm font-black text-ch-white uppercase tracking-tight">Limites & KPIs de Performance</h3>
                                </div>
                                <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
                                    {[
                                        { label: 'CTR MÍNIMO (%)', key: 'ctr_min', icon: Target },
                                        { label: 'CTR ALVO (%)', key: 'ctr_target', icon: TrendingUp },
                                        { label: 'CPC MÁXIMO (R$)', key: 'cpc_max', icon: DollarSign },
                                        { label: 'CPC ALVO (R$)', key: 'cpc_target', icon: Zap },
                                    ].map((field) => (
                                        <div key={field.key} className="space-y-3">
                                            <Label className="text-[9px] font-black text-ch-text-dimmed uppercase tracking-widest">{field.label}</Label>
                                            <div className="relative">
                                                <Input
                                                    type="number"
                                                    value={(form[field.key as keyof CreatePolicyInput] as any)?.toString() || ''}
                                                    onChange={(e) => setForm({ ...form, [field.key]: parseFloat(e.target.value) || undefined })}
                                                    className="bg-ch-dark-gray/40 border-white/5 h-12 rounded-xl pl-4 pr-4 font-black text-sm text-ch-white text-center"
                                                    placeholder="0.0"
                                                />
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            </div>

                            {/* Aesthetics Switching */}
                            <div className="bg-white/[0.02] border border-white/5 p-8 rounded-[2rem] space-y-6">
                                <div className="flex items-center gap-3">
                                    <Briefcase className="w-5 h-5 text-ch-orange" />
                                    <h3 className="text-sm font-black text-ch-white uppercase tracking-tight">Validação Visual de Marca</h3>
                                </div>
                                <div className="flex flex-col md:flex-row gap-8">
                                    <div className="flex items-center gap-4 bg-ch-black/40 p-5 rounded-2xl border border-white/5 flex-1">
                                        <Switch
                                            checked={form.requires_logo}
                                            onCheckedChange={(checked) => setForm({ ...form, requires_logo: checked })}
                                            className="data-[state=checked]:bg-ch-orange"
                                        />
                                        <div>
                                            <Label className="text-[11px] font-black text-ch-white uppercase tracking-widest">Exigir Logotipo</Label>
                                            <p className="text-[9px] font-bold text-ch-text-muted uppercase mt-1">Scanner de visão computacional ativo</p>
                                        </div>
                                    </div>
                                    <div className="flex items-center gap-4 bg-ch-black/40 p-5 rounded-2xl border border-white/5 flex-1">
                                        <Switch
                                            checked={form.requires_brand_colors}
                                            onCheckedChange={(checked) => setForm({ ...form, requires_brand_colors: checked })}
                                            className="data-[state=checked]:bg-ch-orange"
                                        />
                                        <div>
                                            <Label className="text-[11px] font-black text-ch-white uppercase tracking-widest">Cromatismo da Marca</Label>
                                            <p className="text-[9px] font-bold text-ch-text-muted uppercase mt-1">Validação de paleta hex via IA</p>
                                        </div>
                                    </div>
                                </div>
                            </div>

                            {/* Dialog Actions */}
                            <div className="flex justify-end gap-4 pt-4">
                                <Button variant="outline" onClick={handleCloseDialog} className="bg-transparent border-white/5 h-16 rounded-2xl px-8 font-black uppercase text-[11px] tracking-widest hover:bg-white/5 transition-all">
                                    Descartar
                                </Button>
                                <Button
                                    onClick={handleSubmit}
                                    disabled={!form.name || createPolicy.isPending || updatePolicy.isPending}
                                    className="bg-ch-white hover:bg-ch-orange text-ch-black font-black uppercase tracking-widest rounded-2xl h-16 px-10 shadow-xl shadow-white/5 transition-all"
                                >
                                    {(createPolicy.isPending || updatePolicy.isPending) ? (
                                        <Loader2 className="w-5 h-5 animate-spin" />
                                    ) : (
                                        editingPolicy ? 'Atualizar Protocolo' : 'Publicar Protocolo'
                                    )}
                                </Button>
                            </div>
                        </div>
                    </DialogContent>
                </Dialog>
            </motion.div>

            {/* Quick Stats Grid */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                {[
                    { label: 'Biblioteca de Regras', value: policies.length, icon: Shield, color: 'ch-orange' },
                    { label: 'Sistemas Operantes', value: policies.filter(p => p.status === 'active').length, icon: CheckCircle, color: 'emerald-500' },
                    { label: 'Em Desenvolvimento', value: policies.filter(p => p.status === 'draft').length, icon: AlertTriangle, color: 'amber-500' },
                ].map((stat) => (
                    <motion.div key={stat.label} variants={item} whileHover={{ y: -3 }} className="glass-card rounded-3xl p-6 border-white/5 shadow-xl group">
                        <div className="flex items-center gap-4 mb-4">
                            <div className={`p-2.5 bg-${stat.color}/10 rounded-xl`}>
                                <stat.icon className={`w-5 h-5 text-${stat.color}`} />
                            </div>
                            <span className="text-[10px] font-black text-ch-text-muted uppercase tracking-widest">{stat.label}</span>
                        </div>
                        <p className="text-3xl font-black text-ch-white tracking-tighter tabular-nums group-hover:text-ch-orange transition-colors">{stat.value}</p>
                    </motion.div>
                ))}
            </div>

            {/* Global Search Interface */}
            <motion.div variants={item} className="glass-card rounded-3xl p-4 border-white/5 relative overflow-hidden group">
                <Search className="absolute left-6 top-1/2 -translate-y-1/2 w-5 h-5 text-ch-text-dimmed group-focus-within:text-ch-orange transition-colors" />
                <Input
                    placeholder="PESQUISAR NOS MANUAIS DE COMPLIANCE..."
                    value={search}
                    onChange={(e) => setSearch(e.target.value)}
                    className="pl-14 bg-transparent border-none text-[11px] font-black uppercase tracking-wider h-14 focus-visible:ring-0 placeholder:opacity-20"
                />
            </motion.div>

            {/* Policies Architecture List */}
            {isLoading ? (
                <div className="p-24 flex flex-col items-center justify-center gap-4">
                    <Loader2 className="w-10 h-10 animate-spin text-ch-orange opacity-40" />
                    <span className="text-[10px] font-black uppercase tracking-widest text-ch-text-dimmed">Descriptografando manuais...</span>
                </div>
            ) : filteredPolicies.length > 0 ? (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                    {filteredPolicies.map((policy) => (
                        <motion.div
                            key={policy.id}
                            variants={item}
                            whileHover={{ y: -5 }}
                            className="glass-premium rounded-[2.5rem] p-8 space-y-8 border-white/10 shadow-2xl relative overflow-hidden group hover:bg-ch-black-soft transition-all duration-500"
                        >
                            <div className="absolute top-0 right-0 p-10 opacity-[0.02] pointer-events-none group-hover:opacity-[0.06] transition-opacity">
                                <Shield className="w-32 h-32" />
                            </div>

                            <div className="flex items-start justify-between relative z-10">
                                <div className="flex-1 min-w-0 pr-4">
                                    <h3 className="text-lg font-black text-ch-white uppercase tracking-tight group-hover:text-ch-orange transition-colors truncate">{policy.name}</h3>
                                    <p className="text-[10px] font-medium text-ch-text-dimmed line-clamp-2 mt-2 leading-relaxed">
                                        {policy.description || 'ESTE PROTOCOLO NÃO POSSUI UMA DESCRIÇÃO TÉCNICA DEFINIDA.'}
                                    </p>
                                </div>
                                <DropdownMenu>
                                    <DropdownMenuTrigger asChild>
                                        <Button variant="ghost" size="icon" className="h-10 w-10 bg-white/[0.02] border border-white/5 rounded-xl hover:text-ch-orange">
                                            <MoreHorizontal className="w-5 h-5" />
                                        </Button>
                                    </DropdownMenuTrigger>
                                    <DropdownMenuContent align="end" className="bg-ch-black-soft border-white/10 w-48 font-black uppercase text-[10px] tracking-widest">
                                        <DropdownMenuItem onClick={() => handleEdit(policy)} className="py-3 cursor-pointer">
                                            <Edit2 className="w-4 h-4 mr-3 text-blue-400" /> Editar Regra
                                        </DropdownMenuItem>
                                        <DropdownMenuItem
                                            onClick={() => handleDelete(policy.id)}
                                            className="py-3 text-rose-500 focus:text-rose-500 cursor-pointer"
                                        >
                                            <Trash2 className="w-4 h-4 mr-3" /> Excluir Regra
                                        </DropdownMenuItem>
                                    </DropdownMenuContent>
                                </DropdownMenu>
                            </div>

                            <div className="flex flex-wrap gap-2.5 relative z-10">
                                {getStatusBadge(policy.status)}
                                {getScopeBadge(policy.scope)}
                                {policy.is_default && (
                                    <span className="text-[9px] font-black uppercase tracking-widest px-2.5 py-1 rounded-full bg-ch-orange/10 text-ch-orange border border-ch-orange/20 animate-pulse">
                                        Núcleo
                                    </span>
                                )}
                            </div>

                            <div className="grid grid-cols-2 gap-4 relative z-10 bg-white/[0.02] p-5 rounded-3xl border border-white/5 shadow-inner">
                                <div className="space-y-4">
                                    <div className="flex items-center gap-2">
                                        <CheckCircle className={`w-3.5 h-3.5 ${(policy.required_keywords?.length ?? 0) > 0 ? 'text-emerald-500' : 'text-ch-text-muted opacity-30'}`} />
                                        <span className={`text-[10px] font-black uppercase tracking-tight ${(policy.required_keywords?.length ?? 0) > 0 ? 'text-ch-white' : 'text-ch-text-muted opacity-30'}`}>
                                            {policy.required_keywords?.length || 0} REQUISITOS
                                        </span>
                                    </div>
                                    <div className="flex items-center gap-2">
                                        <Ban className={`w-3.5 h-3.5 ${(policy.prohibited_keywords?.length ?? 0) > 0 ? 'text-rose-500' : 'text-ch-text-muted opacity-30'}`} />
                                        <span className={`text-[10px] font-black uppercase tracking-tight ${(policy.prohibited_keywords?.length ?? 0) > 0 ? 'text-ch-white' : 'text-ch-text-muted opacity-30'}`}>
                                            {policy.prohibited_keywords?.length || 0} BLOQUEIOS
                                        </span>
                                    </div>
                                </div>
                                <div className="space-y-4 border-l border-white/5 pl-4">
                                    <div className="flex items-center gap-2">
                                        <Target className={`w-3.5 h-3.5 ${policy.ctr_min ? 'text-ch-orange' : 'text-ch-text-muted opacity-30'}`} />
                                        <span className={`text-[10px] font-black uppercase tracking-tight ${policy.ctr_min ? 'text-ch-white' : 'text-ch-text-muted opacity-30'}`}>
                                            CTR {policy.ctr_min}%+
                                        </span>
                                    </div>
                                    <div className="flex items-center gap-2">
                                        <DollarSign className={`w-3.5 h-3.5 ${policy.cpc_max ? 'text-blue-400' : 'text-ch-text-muted opacity-30'}`} />
                                        <span className={`text-[10px] font-black uppercase tracking-tight ${policy.cpc_max ? 'text-ch-white' : 'text-ch-text-muted opacity-30'}`}>
                                            CPC R${policy.cpc_max}
                                        </span>
                                    </div>
                                </div>
                            </div>

                            <div className="text-[9px] font-black text-ch-text-dimmed pt-4 border-t border-white/5 flex items-center gap-2 uppercase tracking-widest relative z-10">
                                <Activity className="w-3 h-3" /> IMPLEMENTADO EM {format(new Date(policy.created_at), "dd/MM/yyyy", { locale: ptBR })}
                            </div>
                        </motion.div>
                    ))}
                </div>
            ) : (
                <div className="glass-premium rounded-[3rem] p-24 text-center border-white/5 shadow-2xl">
                    <div className="w-24 h-24 bg-ch-orange/5 border border-ch-orange/10 rounded-[2.5rem] flex items-center justify-center mx-auto mb-8">
                        <Shield className="w-10 h-10 text-ch-orange animate-pulse" />
                    </div>
                    <h3 className="text-xl font-black text-ch-white uppercase tracking-tight mb-3">Ausência de Proteção</h3>
                    <p className="text-ch-text-muted font-medium max-w-sm mx-auto mb-8">Sua infraestrutura de compliance está vazia. Crie sua primeira política para blindar seus anúncios.</p>
                    <Button onClick={() => setIsDialogOpen(true)} className="bg-ch-orange hover:bg-ch-orange-hover text-ch-black font-black uppercase text-[11px] tracking-widest h-14 px-10 rounded-[1.5rem] shadow-xl shadow-ch-orange/20 transition-all">
                        Implementar Protocolo Alfa
                    </Button>
                </div>
            )}
        </motion.div>
    );
}

import { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '@/contexts/AuthContext';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { useToast } from '@/hooks/use-toast';
import { Eye, EyeOff, Loader2 } from 'lucide-react';

export default function Register() {
    const [formData, setFormData] = useState({
        firstName: '',
        lastName: '',
        email: '',
        password: '',
        confirmPassword: '',
        companyName: '',
    });
    const [showPassword, setShowPassword] = useState(false);
    const [loading, setLoading] = useState(false);
    const { signUp } = useAuth();
    const navigate = useNavigate();
    const { toast } = useToast();

    const updateField = (field: string, value: string) => {
        setFormData(prev => ({ ...prev, [field]: value }));
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();

        const { firstName, lastName, email, password, confirmPassword, companyName } = formData;

        // Validation
        if (!email || !password || !firstName || !companyName) {
            toast({
                title: 'Campos obrigatórios',
                description: 'Por favor, preencha todos os campos obrigatórios.',
                variant: 'destructive',
            });
            return;
        }

        if (password.length < 6) {
            toast({
                title: 'Senha muito curta',
                description: 'A senha deve ter pelo menos 6 caracteres.',
                variant: 'destructive',
            });
            return;
        }

        if (password !== confirmPassword) {
            toast({
                title: 'Senhas não conferem',
                description: 'As senhas digitadas não são iguais.',
                variant: 'destructive',
            });
            return;
        }

        setLoading(true);
        const { error } = await signUp(email, password, {
            first_name: firstName,
            last_name: lastName,
            company_name: companyName,
        });
        setLoading(false);

        if (error) {
            toast({
                title: 'Erro ao criar conta',
                description: error.message,
                variant: 'destructive',
            });
        } else {
            toast({
                title: 'Conta criada!',
                description: 'Verifique seu email para confirmar sua conta.',
            });
            navigate('/login');
        }
    };

    return (
        <div className="space-y-6 w-full max-w-md mx-auto">
            {/* Logo */}
            <div className="text-center">
                <div className="flex justify-center mb-4">
                    <div className="w-12 h-12 bg-ch-orange rounded-xl flex items-center justify-center">
                        <span className="font-bold text-ch-black text-2xl">C</span>
                    </div>
                </div>
                <h1 className="text-2xl font-bold gradient-text">Click Auditor</h1>
                <p className="text-ch-text-muted mt-2">Crie sua conta para começar</p>
            </div>

            {/* Form */}
            <div className="glass rounded-xl p-6 space-y-4">
                <form onSubmit={handleSubmit} className="space-y-4">
                    <div className="grid grid-cols-2 gap-3">
                        <div className="space-y-2">
                            <Label htmlFor="firstName">Nome *</Label>
                            <Input
                                id="firstName"
                                placeholder="João"
                                value={formData.firstName}
                                onChange={(e) => updateField('firstName', e.target.value)}
                                className="bg-ch-black border-white/10 focus:border-ch-orange"
                                disabled={loading}
                            />
                        </div>
                        <div className="space-y-2">
                            <Label htmlFor="lastName">Sobrenome</Label>
                            <Input
                                id="lastName"
                                placeholder="Silva"
                                value={formData.lastName}
                                onChange={(e) => updateField('lastName', e.target.value)}
                                className="bg-ch-black border-white/10 focus:border-ch-orange"
                                disabled={loading}
                            />
                        </div>
                    </div>

                    <div className="space-y-2">
                        <Label htmlFor="companyName">Nome da Empresa *</Label>
                        <Input
                            id="companyName"
                            placeholder="Minha Empresa"
                            value={formData.companyName}
                            onChange={(e) => updateField('companyName', e.target.value)}
                            className="bg-ch-black border-white/10 focus:border-ch-orange"
                            disabled={loading}
                        />
                    </div>

                    <div className="space-y-2">
                        <Label htmlFor="email">Email *</Label>
                        <Input
                            id="email"
                            type="email"
                            placeholder="seu@email.com"
                            value={formData.email}
                            onChange={(e) => updateField('email', e.target.value)}
                            className="bg-ch-black border-white/10 focus:border-ch-orange"
                            disabled={loading}
                        />
                    </div>

                    <div className="space-y-2">
                        <Label htmlFor="password">Senha *</Label>
                        <div className="relative">
                            <Input
                                id="password"
                                type={showPassword ? 'text' : 'password'}
                                placeholder="••••••••"
                                value={formData.password}
                                onChange={(e) => updateField('password', e.target.value)}
                                className="bg-ch-black border-white/10 focus:border-ch-orange pr-10"
                                disabled={loading}
                            />
                            <button
                                type="button"
                                onClick={() => setShowPassword(!showPassword)}
                                className="absolute right-3 top-1/2 -translate-y-1/2 text-ch-text-dimmed hover:text-ch-white transition-colors"
                            >
                                {showPassword ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
                            </button>
                        </div>
                    </div>

                    <div className="space-y-2">
                        <Label htmlFor="confirmPassword">Confirmar Senha *</Label>
                        <Input
                            id="confirmPassword"
                            type="password"
                            placeholder="••••••••"
                            value={formData.confirmPassword}
                            onChange={(e) => updateField('confirmPassword', e.target.value)}
                            className="bg-ch-black border-white/10 focus:border-ch-orange"
                            disabled={loading}
                        />
                    </div>

                    <Button
                        type="submit"
                        className="w-full bg-ch-orange hover:bg-ch-orange-hover text-ch-black font-semibold"
                        disabled={loading}
                    >
                        {loading ? (
                            <>
                                <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                                Criando conta...
                            </>
                        ) : (
                            'Criar Conta'
                        )}
                    </Button>
                </form>

                <div className="text-center text-sm">
                    <span className="text-ch-text-muted">Já tem uma conta? </span>
                    <Link
                        to="/login"
                        className="text-ch-orange hover:text-ch-orange-hover font-medium transition-colors"
                    >
                        Fazer login
                    </Link>
                </div>
            </div>
        </div>
    );
}

import { useState } from 'react';
import { useQuery, useMutation } from '@tanstack/react-query';
import { supabase, supabaseUrl } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from '@/components/ui/select';
import {
    FileText,
    Download,
    Loader2,
    Calendar,
    BarChart3,
    Megaphone,
    Image,
    FileCheck,
    ExternalLink,
    Clock
} from 'lucide-react';
import { format, subDays } from 'date-fns';
import { ptBR } from 'date-fns/locale';
import { toast } from 'sonner';

interface Report {
    id: string;
    report_type: string;
    date_from: string;
    date_to: string;
    created_at: string;
}

const REPORT_TYPES = [
    { value: 'performance', label: 'Performance Geral', icon: BarChart3 },
    { value: 'campaigns', label: 'Campanhas', icon: Megaphone },
    { value: 'creatives', label: 'Criativos', icon: Image },
    { value: 'audits', label: 'Auditorias', icon: FileCheck },
];

export default function Relatorios() {
    const { user } = useAuth();
    const companyId = user?.company?.id;
    const [reportType, setReportType] = useState<string>('performance');
    const [dateFrom, setDateFrom] = useState(format(subDays(new Date(), 30), 'yyyy-MM-dd'));
    const [dateTo, setDateTo] = useState(format(new Date(), 'yyyy-MM-dd'));

    // Fetch report history
    const { data: reports = [], isLoading } = useQuery({
        queryKey: ['reports', companyId],
        queryFn: async () => {
            if (!companyId) throw new Error('No company ID');
            const { data, error } = await supabase
                .from('reports')
                .select('id, report_type, date_from, date_to, created_at')
                .eq('company_id', companyId)
                .order('created_at', { ascending: false })
                .limit(20);
            if (error) throw error;
            return data as Report[];
        },
        enabled: !!companyId,
    });

    const generateReport = useMutation({
        mutationFn: async () => {
            const { data: { session } } = await supabase.auth.getSession();
            if (!session) throw new Error('No session');

            const response = await fetch(
                `${supabaseUrl}/functions/v1/generate-report`,
                {
                    method: 'POST',
                    headers: {
                        'Authorization': `Bearer ${session.access_token}`,
                        'Content-Type': 'application/json',
                    },
                    body: JSON.stringify({
                        report_type: reportType,
                        date_from: dateFrom,
                        date_to: dateTo,
                    }),
                }
            );

            if (!response.ok) {
                const error = await response.json();
                throw new Error(error.error || 'Report generation failed');
            }

            const html = await response.text();
            return html;
        },
        onSuccess: (html) => {
            // Open report in new window
            const win = window.open('', '_blank');
            if (win) {
                win.document.write(html);
                win.document.close();
            }
            toast.success('Relatório gerado com sucesso');
        },
        onError: (error) => {
            toast.error(`Erro ao gerar relatório: ${error.message}`);
        },
    });

    const getReportTypeLabel = (type: string) => {
        return REPORT_TYPES.find(t => t.value === type)?.label || type;
    };

    const getReportIcon = (type: string) => {
        const Icon = REPORT_TYPES.find(t => t.value === type)?.icon || FileText;
        return <Icon className="w-4 h-4" />;
    };

    return (
        <div className="p-8 max-w-6xl mx-auto">
            <div className="mb-8">
                <h1 className="text-2xl font-bold text-ch-white mb-2">Relatórios</h1>
                <p className="text-ch-text-muted">
                    Gere relatórios detalhados de performance, campanhas, criativos e auditorias.
                </p>
            </div>

            {/* Report Generator */}
            <div className="glass rounded-xl p-6 mb-8">
                <h2 className="text-lg font-semibold text-ch-white mb-4 flex items-center gap-2">
                    <FileText className="w-5 h-5 text-ch-orange" />
                    Gerar Novo Relatório
                </h2>

                <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                    <div className="space-y-2">
                        <Label>Tipo de Relatório</Label>
                        <Select value={reportType} onValueChange={setReportType}>
                            <SelectTrigger className="bg-ch-dark-gray border-ch-dark-gray">
                                <SelectValue />
                            </SelectTrigger>
                            <SelectContent>
                                {REPORT_TYPES.map(t => (
                                    <SelectItem key={t.value} value={t.value}>
                                        <div className="flex items-center gap-2">
                                            <t.icon className="w-4 h-4" />
                                            {t.label}
                                        </div>
                                    </SelectItem>
                                ))}
                            </SelectContent>
                        </Select>
                    </div>

                    <div className="space-y-2">
                        <Label>Data Início</Label>
                        <Input
                            type="date"
                            value={dateFrom}
                            onChange={(e) => setDateFrom(e.target.value)}
                            className="bg-ch-dark-gray border-ch-dark-gray"
                        />
                    </div>

                    <div className="space-y-2">
                        <Label>Data Fim</Label>
                        <Input
                            type="date"
                            value={dateTo}
                            onChange={(e) => setDateTo(e.target.value)}
                            className="bg-ch-dark-gray border-ch-dark-gray"
                        />
                    </div>

                    <div className="flex items-end">
                        <Button
                            onClick={() => generateReport.mutate()}
                            disabled={generateReport.isPending}
                            className="w-full bg-ch-orange hover:bg-ch-orange/90"
                        >
                            {generateReport.isPending ? (
                                <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                            ) : (
                                <Download className="w-4 h-4 mr-2" />
                            )}
                            Gerar Relatório
                        </Button>
                    </div>
                </div>
            </div>

            {/* Report History */}
            <div className="glass rounded-xl p-6">
                <h2 className="text-lg font-semibold text-ch-white mb-4 flex items-center gap-2">
                    <Clock className="w-5 h-5 text-ch-orange" />
                    Histórico de Relatórios
                </h2>

                {isLoading ? (
                    <div className="flex items-center justify-center py-8">
                        <Loader2 className="w-6 h-6 animate-spin text-ch-orange" />
                    </div>
                ) : reports.length > 0 ? (
                    <div className="space-y-2">
                        {reports.map((report) => (
                            <div
                                key={report.id}
                                className="bg-ch-dark-gray rounded-lg p-4 flex items-center gap-4"
                            >
                                <div className="p-2 bg-ch-gray rounded-lg text-ch-orange">
                                    {getReportIcon(report.report_type)}
                                </div>
                                <div className="flex-1 min-w-0">
                                    <p className="font-medium text-ch-white">
                                        {getReportTypeLabel(report.report_type)}
                                    </p>
                                    <p className="text-sm text-ch-text-dimmed">
                                        {format(new Date(report.date_from), 'dd/MM/yyyy', { locale: ptBR })} -{' '}
                                        {format(new Date(report.date_to), 'dd/MM/yyyy', { locale: ptBR })}
                                    </p>
                                </div>
                                <div className="text-right">
                                    <p className="text-xs text-ch-text-dimmed">
                                        {format(new Date(report.created_at), "dd/MM/yyyy 'às' HH:mm", { locale: ptBR })}
                                    </p>
                                </div>
                            </div>
                        ))}
                    </div>
                ) : (
                    <div className="text-center py-8">
                        <FileText className="w-12 h-12 text-ch-text-dimmed mx-auto mb-4" />
                        <p className="text-ch-text-muted">Nenhum relatório gerado ainda.</p>
                    </div>
                )}
            </div>
        </div>
    );
}

import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { User, Shield, Sliders } from 'lucide-react';
import { ProfileForm } from '@/components/settings/ProfileForm';
import { SecurityForm } from '@/components/settings/SecurityForm';
import { PreferencesForm } from '@/components/settings/PreferencesForm';
import { motion } from 'framer-motion';

const container = {
    hidden: { opacity: 0 },
    show: {
        opacity: 1,
        transition: {
            staggerChildren: 0.1
        }
    }
};

const item = {
    hidden: { y: 20, opacity: 0 },
    show: { y: 0, opacity: 1 }
};

export default function Settings() {
    return (
        <motion.div
            initial="hidden"
            animate="show"
            variants={container}
            className="space-y-8 p-8"
        >
            <div className="flex items-center justify-between">
                <div>
                    <motion.h1 variants={item} className="text-3xl font-black text-ch-white tracking-tight uppercase">
                        Configurações
                    </motion.h1>
                    <motion.p variants={item} className="text-ch-text-muted font-medium mt-1">
                        Gerencie seu perfil, segurança e preferências.
                    </motion.p>
                </div>
            </div>

            <motion.div variants={item}>
                <Tabs defaultValue="profile" className="space-y-6">
                    <TabsList className="bg-white/5 border border-white/10 p-1 rounded-xl w-full sm:w-auto flex flex-wrap sm:flex-nowrap gap-2 sm:gap-0">
