export default function Usuarios() {
    const { user: currentUser } = useAuth();
    const { data: users, isLoading } = useCompanyUsers();
    const updateUser = useUpdateUser();
    const removeUser = useRemoveUser();

    const handleRoleChange = (userId: string, newRole: 'super_admin' | 'company_admin' | 'operador') => {
        updateUser.mutate({ userId, updates: { role: newRole } });
    };

    const handleRemove = (userId: string, userName: string) => {
        if (confirm(`Tem certeza que deseja desativar ${userName}?`)) {
            removeUser.mutate(userId);
        }
    };

    const getRoleBadge = (role: string) => {
        const colors: Record<string, string> = {
            super_admin: 'bg-purple-500/10 text-purple-500',
            company_admin: 'bg-blue-500/10 text-blue-500',
            operador: 'bg-green-500/10 text-green-500',
        };
        const labels: Record<string, string> = {
            super_admin: 'Super Admin',
            company_admin: 'Admin',
            operador: 'Operador',
        };
        return (
            <span className={`text-xs px-2 py-1 rounded-full ${colors[role] || 'bg-gray-500/10 text-gray-400'}`}>
                {labels[role] || role}
            </span>
        );
    };

    const activeUsers = users?.filter(u => u.is_active) || [];
    const inactiveUsers = users?.filter(u => !u.is_active) || [];

