import { serve } from 'https://deno.land/std@0.168.0/http/server.ts';
import { createClient } from 'https://esm.sh/@supabase/supabase-js@2';

const corsHeaders = {
    'Access-Control-Allow-Origin': '*',
    'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
};

interface BatchAuditRequest {
    campaign_id?: string;
    policy_id?: string;
    limit?: number;
}

serve(async (req) => {
    if (req.method === 'OPTIONS') {
        return new Response('ok', { headers: corsHeaders });
    }

    try {
        const supabaseUrl = Deno.env.get('SUPABASE_URL')!;
        const supabaseServiceKey = Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!;
        const supabase = createClient(supabaseUrl, supabaseServiceKey);

        const authHeader = req.headers.get('Authorization');
        if (!authHeader) {
            throw new Error('Missing authorization header');
        }

        const { data: { user }, error: authError } = await supabase.auth.getUser(
            authHeader.replace('Bearer ', '')
        );
        if (authError || !user) {
            throw new Error('Unauthorized');
        }

        const { data: userData } = await supabase
            .from('users')
            .select('company_id')
            .eq('id', user.id)
            .single();

        if (!userData?.company_id) {
            throw new Error('User not associated with company');
        }

        const { campaign_id, policy_id, limit = 50 } = await req.json() as BatchAuditRequest;

        // Get creatives to audit
        let query = supabase
            .from('creatives')
            .select('id')
            .eq('company_id', userData.company_id)
            .limit(limit);

        if (campaign_id) {
            query = query.eq('campaign_id', campaign_id);
        }

        const { data: creatives, error: creativesError } = await query;

        if (creativesError) {
            throw new Error('Failed to fetch creatives');
        }

        if (!creatives?.length) {
            return new Response(
                JSON.stringify({
                    success: true,
                    message: 'No creatives to audit',
                    audited: 0,
                }),
                {
                    headers: { ...corsHeaders, 'Content-Type': 'application/json' },
                    status: 200,
                }
            );
        }

        // Call audit-creative for each creative
        const auditUrl = `${supabaseUrl}/functions/v1/audit-creative`;
        const results = {
            success: 0,
            failed: 0,
            errors: [] as string[],
        };

        for (const creative of creatives) {
            try {
                const response = await fetch(auditUrl, {
                    method: 'POST',
                    headers: {
                        'Authorization': authHeader,
                        'Content-Type': 'application/json',
                    },
                    body: JSON.stringify({
                        creative_id: creative.id,
                        policy_id,
                    }),
                });

                if (response.ok) {
                    results.success++;
                } else {
                    results.failed++;
                    const errorData = await response.json();
                    results.errors.push(`Creative ${creative.id}: ${errorData.error}`);
                }
            } catch (error) {
                results.failed++;
                results.errors.push(`Creative ${creative.id}: ${String(error)}`);
            }

            // Small delay to avoid rate limiting
            await new Promise(resolve => setTimeout(resolve, 100));
        }

        // Log batch audit
        await supabase.from('sync_history').insert({
            company_id: userData.company_id,
            sync_type: 'batch_audit',
            status: 'completed',
            records_synced: results.success,
            details: {
                total: creatives.length,
                success: results.success,
                failed: results.failed,
                campaign_id,
                policy_id,
            },
        });

        return new Response(
            JSON.stringify({
                success: true,
                total: creatives.length,
                audited: results.success,
                failed: results.failed,
                errors: results.errors.slice(0, 5), // Return first 5 errors only
            }),
            {
                headers: { ...corsHeaders, 'Content-Type': 'application/json' },
                status: 200,
            }
        );

    } catch (error) {
        console.error('Batch audit error:', error);
        return new Response(
            JSON.stringify({
                success: false,
                error: String(error),
            }),
            {
                headers: { ...corsHeaders, 'Content-Type': 'application/json' },
                status: 400,
            }
        );
    }
});

